  const [thumbnailFile, setThumbnailFile] = useState<File | null>(null);
  const [thumbnailPreview, setThumbnailPreview] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState(false);

  const handleThumbnailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setThumbnailFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setThumbnailPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleVideoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      setVideoFile(e.target.files[0]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !videoFile || !thumbnailPreview) {
      alert("Please provide at least a title, video, and thumbnail.");
      return;
    }

    setIsUploading(true);

    try {
      // Create a playable local URL for immediate state update
      const videoUrl = URL.createObjectURL(videoFile);
      const movieId = Math.random().toString(36).substring(2, 9);

      const newMovie: Movie = {
        id: movieId,
        title,
        description,
        thumbnail: thumbnailPreview,
        videoUrl: videoUrl,
        genre,
        year: new Date().getFullYear(),
        rating: 'NR',
        isUserUploaded: true
      };

      // Save to IndexedDB for cross-session persistence (simulated cloud)
      await saveVideoToDB(newMovie, videoFile);

      // Processing delay for UX
      await new Promise(r => setTimeout(r, 2000));

      onUpload(newMovie);
      setIsUploading(false);
      onClose();
    } catch (err) {
      console.error(err);
      alert("Failed to upload video to local cloud storage.");
      setIsUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm overflow-y-auto">
      <div className="bg-[#181818] w-full max-w-xl my-auto rounded-2xl overflow-hidden shadow-2xl border border-white/10 animate-in slide-in-from-bottom-4 duration-300">
        <div className="p-6 border-b border-white/10 flex items-center justify-between">
          <h2 className="text-xl font-bold flex items-center text-white">
            <Upload className="w-5 h-5 mr-2 text-red-600" />
            Upload Your Content
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-red-500 transition">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1">Movie Title</label>
              <input 
                type="text" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full bg-[#2a2a2a] border border-white/10 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-red-600 outline-none transition"
                placeholder="The Future Awakens..."
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1">Description</label>
              <textarea 
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full bg-[#2a2a2a] border border-white/10 rounded-lg px-4 py-2 text-white h-24 focus:ring-2 focus:ring-red-600 outline-none transition resize-none"
                placeholder="Describe your masterpiece..."
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Genre</label>
                  <select 
                    value={genre}
                    onChange={(e) => setGenre(e.target.value)}
                    className="w-full bg-[#2a2a2a] border border-white/10 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-red-600 outline-none transition appearance-none"
                  >
                    <option>Sci-Fi</option>
                    <option>Action</option>
                    <option>Documentary</option>
                    <option>Vlog</option>
                    <option>Comedy</option>
                    <option>Horror</option>
                  </select>
               </div>
               <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Rating</label>
                  <div className="w-full bg-black/20 text-gray-500 border border-white/5 rounded-lg px-4 py-2 italic text-xs">
                    Auto-set: NR (Not Rated)
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               <label className="flex flex-col items-center justify-center border-2 border-dashed border-white/10 rounded-xl p-4 cursor-pointer hover:border-red-600 transition group h-32">
                  <Film className={`w-8 h-8 ${videoFile ? 'text-green-500' : 'text-gray-500 group-hover:text-red-500'}`} />
                  <span className="text-[10px] mt-2 font-bold uppercase tracking-widest text-gray-500 text-center">
                    {videoFile ? videoFile.name : 'Select Video File'}
                  </span>
                  <input type="file" accept="video/*" className="hidden" onChange={handleVideoChange} required />
               </label>

               <label className="relative flex flex-col items-center justify-center border-2 border-dashed border-white/10 rounded-xl p-4 cursor-pointer hover:border-red-600 transition group h-32 overflow-hidden">
                  {thumbnailPreview ? (
                    <img src={thumbnailPreview} className="absolute inset-0 w-full h-full object-cover opacity-60" alt="" />
                  ) : (
                    <ImageIcon className="w-8 h-8 text-gray-500 group-hover:text-red-500" />
                  )}
                  <span className="relative text-[10px] mt-2 font-bold uppercase tracking-widest text-white shadow-sm">
                    {thumbnailFile ? 'Thumbnail Ready' : 'Select Poster Image'}
                  </span>
                  <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} required />
               </label>
            </div>
          </div>

          <button 
            type="submit" 
            disabled={isUploading}
            className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-lg transition disabled:opacity-50 flex items-center justify-center shadow-lg active:scale-95"
          >
            {isUploading ? (
              <>
                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                Uploading to Gemini Cloud...
              </>
            ) : (
              'Publish to GeminiStream'
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default UploadModal;

import React, { useState, useMemo, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import MovieRow from './components/MovieRow.tsx';
import MovieDetails from './components/MovieDetails.tsx';
import UploadModal from './components/UploadModal.tsx';
import VideoPlayer from './components/VideoPlayer.tsx';
import LoginModal from './components/LoginModal.tsx';
import { INITIAL_MOVIES } from './constants.ts';
import { Movie, User } from './types.ts';
import { getAllVideosFromDB } from './services/storageService.ts';

const STORAGE_KEYS = {
  HISTORY: 'gemini_stream_history',
  USER: 'gemini_stream_user'
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [movies, setMovies] = useState<Movie[]>(INITIAL_MOVIES);
  const [historyIds, setHistoryIds] = useState<string[]>([]);
  const [selectedMovie, setSelectedMovie] = useState<Movie | null>(null);
  const [playingMovie, setPlayingMovie] = useState<Movie | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(true);

  // Initial Load from Persistence
  useEffect(() => {
    const savedUser = localStorage.getItem(STORAGE_KEYS.USER);
    if (savedUser) setUser(JSON.parse(savedUser));

    const savedHistory = localStorage.getItem(STORAGE_KEYS.HISTORY);
    if (savedHistory) setHistoryIds(JSON.parse(savedHistory));

    const syncCommunityContent = async () => {
      try {
        const communityVideos = await getAllVideosFromDB();
        setMovies(prev => {
          // Merge initial movies with community videos, avoiding duplicates
          const initialIds = new Set(INITIAL_MOVIES.map(m => m.id));
          const filteredPrev = prev.filter(m => initialIds.has(m.id));
          return [...communityVideos, ...filteredPrev];
        });
      } catch (err) {
        console.error("Sync Error:", err);
      } finally {
        setIsSyncing(false);
      }
    };

    syncCommunityContent();
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(newUser));
    setShowLoginModal(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem(STORAGE_KEYS.USER);
  };

  const handleUpload = (newMovie: Movie) => {
    const uploadedMovie = {
      ...newMovie,
      uploaderId: user?.id,
      uploaderName: user?.name
    };

    setMovies(prev => [uploadedMovie, ...prev]);
  };

  const handlePlay = (movie: Movie) => {
    setSelectedMovie(null);
    setPlayingMovie(movie);

    if (!historyIds.includes(movie.id)) {
      const newHistory = [movie.id, ...historyIds].slice(0, 20);
      setHistoryIds(newHistory);
      localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));
    }
  };

  const featuredMovie = useMemo(() => {
    const scifi = movies.filter(m => m.genre === 'Sci-Fi');
    return scifi.length > 0 ? scifi[0] : movies[0];
  }, [movies]);

  const filteredMovies = useMemo(() => {
    if (!searchTerm) return movies;
    return movies.filter(m => 
      m.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
      m.genre.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [movies, searchTerm]);

  const historyMovies = useMemo(() => {
    return historyIds
      .map(id => movies.find(m => m.id === id))
      .filter((m): m is Movie => !!m);
  }, [historyIds, movies]);

  const rows = useMemo(() => {
    const userCreated = filteredMovies.filter(m => m.isUserUploaded);
    const myUploads = userCreated.filter(m => m.uploaderId === user?.id);
    const othersUploads = userCreated.filter(m => m.uploaderId !== user?.id);

    return [
      { title: 'Trending Now', movies: filteredMovies.slice(0, 10) },
      { title: 'Shared by Community', movies: othersUploads },
      { title: 'Continue Watching', movies: historyMovies },
      { title: 'My Studio Uploads', movies: myUploads },
      { title: 'Sci-Fi Universe', movies: filteredMovies.filter(m => m.genre === 'Sci-Fi') },
      { title: 'Pure Action', movies: filteredMovies.filter(m => m.genre === 'Action') },
    ];
  }, [filteredMovies, historyMovies, user]);

  return (
    <div className="relative min-h-screen pb-20 overflow-x-hidden">
      <Navbar 
        user={user}
        onUploadClick={() => user ? setShowUploadModal(true) : setShowLoginModal(true)} 
        onLoginClick={() => setShowLoginModal(true)}
        onLogout={handleLogout}
        onSearch={setSearchTerm}
      />

      {!searchTerm && (
        <Hero 
          movie={featuredMovie} 
          onInfoClick={setSelectedMovie} 
          onPlay={handlePlay}
        />
      )}

      <div className={`${searchTerm ? 'pt-24' : '-mt-32 relative z-20'} transition-all duration-500`}>
        {isSyncing && (
           <div className="px-4 md:px-12 mb-4 flex items-center space-x-2 text-xs text-red-500 animate-pulse">
              <div className="w-2 h-2 bg-red-500 rounded-full" />
              <span>Syncing Community Cloud...</span>
           </div>
        )}

        {searchTerm && (
          <div className="px-4 md:px-12 mb-8">
            <h2 className="text-3xl font-bold mb-2">Search results for "{searchTerm}"</h2>
            <p className="text-gray-500">{filteredMovies.length} items found</p>
          </div>
        )}

        {rows.map((row, idx) => (
          <MovieRow 
            key={row.title + idx}
            title={row.title}
            movies={row.movies}
            onMovieClick={setSelectedMovie}
          />
        ))}

        {filteredMovies.length === 0 && (
           <div className="flex flex-col items-center justify-center py-40 opacity-50">
              <p className="text-2xl font-light">No matches found in our galaxy.</p>
           </div>
        )}
      </div>

      {selectedMovie && (
        <MovieDetails 
          movie={selectedMovie} 
          onClose={() => setSelectedMovie(null)} 
          onPlay={handlePlay}
        />
      )}

      {playingMovie && (
        <VideoPlayer 
          movie={playingMovie} 
          onClose={() => setPlayingMovie(null)} 
        />
      )}

      {showUploadModal && (
        <UploadModal 
          onClose={() => setShowUploadModal(false)} 
          onUpload={handleUpload}
        />
      )}

      {showLoginModal && (
        <LoginModal 
          onLogin={handleLogin}
          onClose={() => setShowLoginModal(false)}
        />
      )}

      <footer className="px-4 md:px-12 py-12 border-t border-white/5 text-gray-600 text-sm mt-20">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 max-w-6xl mx-auto">
          <div className="flex flex-col space-y-3">
            <span className="hover:underline cursor-pointer">Audio Description</span>
            <span className="hover:underline cursor-pointer">Help Center</span>
          </div>
          <div className="flex flex-col space-y-3">
            <span className="hover:underline cursor-pointer">Media Center</span>
            <span className="hover:underline cursor-pointer">Jobs</span>
          </div>
          <div className="flex flex-col space-y-3">
            <span className="hover:underline cursor-pointer">Terms of Use</span>
            <span className="hover:underline cursor-pointer">Privacy</span>
          </div>
          <div className="flex flex-col space-y-3">
            <span className="hover:underline cursor-pointer">Contact Us</span>
          </div>
        </div>
        <p className="mt-12 text-center text-xs tracking-widest uppercase">© 2024 GeminiStream. Authenticated via Google. Global community sync active.</p>
      </footer>
    </div>
  );
};

export default App;

import { User } from '../types.ts';

const USERS_KEY = 'gemini_stream_mobile_users';

interface RegisteredUser extends User {
  password?: string;
  mobile?: string;
}

export const signUpMobile = (name: string, mobile: string, password: string): User | string => {
  const users: RegisteredUser[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');

  if (users.some(u => u.mobile === mobile)) {
    return "This mobile number is already registered.";
  }

  const newUser: RegisteredUser = {
    id: 'mob_' + Math.random().toString(36).substr(2, 9),
    name,
    email: `${mobile}@geministream.com`,
    mobile,
    password, // In a real app, this would be hashed
    avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=E50914&color=fff`
  };

  users.push(newUser);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));

  const { password: _, ...userWithoutPassword } = newUser;
  return userWithoutPassword;
};

export const loginMobile = (mobile: string, password: string): User | string => {
  const users: RegisteredUser[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
  const user = users.find(u => u.mobile === mobile && u.password === password);

  if (!user) {
    return "Invalid mobile number or password.";
  }

  const { password: _, ...userWithoutPassword } = user;
  return userWithoutPassword;
};

import React, { useState } from 'react';
import { User as UserType } from '../types.ts';
import { User, ChevronRight, Phone, Lock, UserPlus, LogIn, ArrowLeft } from 'lucide-react';
import { signUpMobile, loginMobile } from '../services/authService.ts';

interface LoginModalProps {
  onLogin: (user: UserType) => void;
  onClose: () => void;
}

type AuthMode = 'google' | 'mobile-signin' | 'mobile-signup';

const LoginModal: React.FC<LoginModalProps> = ({ onLogin, onClose }) => {
  const [mode, setMode] = useState<AuthMode>('google');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Form states
  const [name, setName] = useState('');
  const [mobile, setMobile] = useState('');
  const [password, setPassword] = useState('');

  const handleLoginSuccess = (user: UserType) => {
    setLoading(true);
    setError(null);
    setTimeout(() => {
      onLogin(user);
      setLoading(false);
    }, 1200);
  };

  const handleGoogleMock = (user: UserType) => {
    handleLoginSuccess(user);
  };

  const handleMobileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'mobile-signup') {
      const result = signUpMobile(name, mobile, password);
      if (typeof result === 'string') {
        setError(result);
      } else {
        handleLoginSuccess(result);
      }
    } else {
      const result = loginMobile(mobile, password);
      if (typeof result === 'string') {
        setError(result);
      } else {
        handleLoginSuccess(result);
      }
    }
  };

  const mockGoogleAccounts = [
    { name: 'Google User', email: 'user@gmail.com', avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=100&auto=format&fit=crop' },
    { name: 'Creative Mind', email: 'creator@gmail.com', avatar: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=100&auto=format&fit=crop' }
  ];

  if (loading) {
    return (
      <div className="fixed inset-0 z-[150] flex items-center justify-center bg-black/95 backdrop-blur-sm">
        <div className="text-center space-y-4">
          <div className="w-12 h-12 border-4 border-red-600/20 border-t-red-600 rounded-full animate-spin mx-auto" />
          <p className="text-gray-400 font-medium">Securing your session...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md overflow-y-auto">
      <div className="bg-[#181818] text-white w-full max-w-[450px] rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 border border-white/10">

        {/* Header Toggle */}
        <div className="flex border-b border-white/5">
          <button 
            onClick={() => { setMode('google'); setError(null); }}
            className={`flex-1 py-4 text-sm font-bold transition-all ${mode === 'google' ? 'text-red-600 border-b-2 border-red-600' : 'text-gray-500 hover:text-white'}`}
          >
            Google
          </button>
          <button 
            onClick={() => { setMode('mobile-signin'); setError(null); }}
            className={`flex-1 py-4 text-sm font-bold transition-all ${mode !== 'google' ? 'text-red-600 border-b-2 border-red-600' : 'text-gray-500 hover:text-white'}`}
          >
            Mobile
          </button>
        </div>

        <div className="p-8">
          {mode === 'google' ? (
            <div className="space-y-6">
              <div className="text-center space-y-2">
                <h2 className="text-2xl font-bold">Sign in with Google</h2>
                <p className="text-sm text-gray-400">Choose an account from your device</p>
              </div>

              <div className="space-y-2">
                {mockGoogleAccounts.map((acc) => (
                  <button
                    key={acc.email}
                    onClick={() => handleGoogleMock({ id: acc.email, ...acc })}
                    className="w-full flex items-center p-3 bg-white/5 hover:bg-white/10 transition rounded-xl border border-white/5"
                  >
                    <img src={acc.avatar} className="w-10 h-10 rounded-full mr-4 border border-white/10" alt="" />
                    <div className="flex-1 text-left overflow-hidden">
                      <p className="text-sm font-bold truncate">{acc.name}</p>
                      <p className="text-xs text-gray-500 truncate">{acc.email}</p>
                    </div>
                    <ChevronRight className="w-4 h-4 text-gray-600" />
                  </button>
                ))}
              </div>

              <p className="text-[10px] text-gray-500 text-center leading-relaxed">
                By continuing, GeminiStream will have access to your basic profile information to personalize your streaming experience.
              </p>
            </div>
          ) : (
            <form onSubmit={handleMobileSubmit} className="space-y-6">
              <div className="text-center space-y-2">
                <h2 className="text-2xl font-bold">
                  {mode === 'mobile-signin' ? 'Welcome Back' : 'Join GeminiStream'}
                </h2>
                <p className="text-sm text-gray-400">
                  {mode === 'mobile-signin' ? 'Sign in with your mobile number' : 'Create an account to start streaming'}
                </p>
              </div>

              {error && (
                <div className="bg-red-500/10 border border-red-500/20 p-3 rounded-lg text-red-500 text-xs text-center font-medium animate-in slide-in-from-top-1">
                  {error}
                </div>
              )}

              <div className="space-y-4">
                {mode === 'mobile-signup' && (
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                    <input
                      type="text"
                      placeholder="Full Name"
                      required
                      className="w-full bg-white/5 border border-white/10 rounded-xl pl-12 pr-4 py-3 focus:border-red-600 outline-none transition"
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                    />
                  </div>
                )}

                <div className="relative">
                  <Phone className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                  <input
                    type="tel"
                    placeholder="Mobile Number"
                    required
                    className="w-full bg-white/5 border border-white/10 rounded-xl pl-12 pr-4 py-3 focus:border-red-600 outline-none transition"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value)}
                  />
                </div>

                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                  <input
                    type="password"
                    placeholder="Password"
                    required
                    className="w-full bg-white/5 border border-white/10 rounded-xl pl-12 pr-4 py-3 focus:border-red-600 outline-none transition"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                </div>
              </div>

              <button
                type="submit"
                className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-xl transition flex items-center justify-center space-x-2 active:scale-[0.98] shadow-lg shadow-red-600/20"
              >
                {mode === 'mobile-signin' ? <LogIn className="w-5 h-5" /> : <UserPlus className="w-5 h-5" />}
                <span>{mode === 'mobile-signin' ? 'Sign In' : 'Sign Up Now'}</span>
              </button>

              <div className="text-center pt-2">
                <button
                  type="button"
                  onClick={() => {
                    setMode(mode === 'mobile-signin' ? 'mobile-signup' : 'mobile-signin');
                    setError(null);
                  }}
                  className="text-sm text-gray-400 hover:text-white transition"
                >
                  {mode === 'mobile-signin' ? "New here? Sign up now." : "Already have an account? Sign in."}
                </button>
              </div>
            </form>
          )}

          <div className="mt-8 flex justify-center">
            <button 
              onClick={onClose}
              className="flex items-center text-xs text-gray-500 hover:text-white transition group"
            >
              <ArrowLeft className="w-3 h-3 mr-1 group-hover:-translate-x-1 transition-transform" />
              Not now, just browsing
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginModal;

payload.text:
To register users and persist their data (like videos) on Vercel so that **all users** can see them regardless of their device, you need to move beyond browser storage (`localStorage`/`IndexedDB`) and use a real backend and database.

Vercel provides several built-in solutions for this:

### 1. **Vercel Blob** (For Videos & Thumbnails)
Browser storage is limited (usually 50MB–250MB). To store high-quality videos that others can watch, you use **Vercel Blob**.
- **Process**: When a user uploads a video in your `UploadModal`, the file is sent to a Vercel Serverless Function. The function saves it to Vercel Blob and returns a permanent URL (e.g., `https://account.public.blob.vercel-storage.com/video123.mp4`).
- **Sharing**: This URL is public, so any other user can load it in their video player.

### 2. **Vercel Postgres** (For Users & Movie Metadata)
To "remember" users and link them to their videos, you use a relational database like **Vercel Postgres**.
- **Users Table**: Stores mobile numbers, hashed passwords, and names.
- **Movies Table**: Stores the title, description, and the **URL** provided by Vercel Blob.
- **Relationship**: Each movie entry in the database includes an `uploaderId`, allowing the app to show "Uploaded by [Name]" to everyone.

### 3. **Vercel KV** (For Watch History)
For fast, temporary data like "where a user left off" in a video or their "recent searches," **Vercel KV** (a serverless Redis) is the standard choice.

