export const publishToVercel = async (file: File, metadata: any) => {
  // 1. Upload to Vercel Blob
  const blob = await fetch('/api/upload', { 
    method: 'POST', 
    body: file 
  }).then(r => r.json());

  // 2. Save metadata to Vercel Postgres
  await fetch('/api/movies', {
    method: 'POST',
    body: JSON.stringify({ ...metadata, videoUrl: blob.url })
  });
};
```

