import React, { useState, useMemo, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import MovieRow from './components/MovieRow.tsx';
import MovieDetails from './components/MovieDetails.tsx';
import UploadModal from './components/UploadModal.tsx';
import VideoPlayer from './components/VideoPlayer.tsx';
import LoginModal from './components/LoginModal.tsx';
import { INITIAL_MOVIES } from './constants.ts';
import { Movie, User } from './types.ts';
import { getAllVideosFromCloud } from './services/storageService.ts';
import { supabase } from './services/supabaseClient.ts';
import { signOut } from './services/authService.ts';

const STORAGE_KEYS = {
  HISTORY: 'gemini_stream_history',
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [movies, setMovies] = useState<Movie[]>(INITIAL_MOVIES);
  const [historyIds, setHistoryIds] = useState<string[]>([]);
  const [selectedMovie, setSelectedMovie] = useState<Movie | null>(null);
  const [playingMovie, setPlayingMovie] = useState<Movie | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(true);

  // Load Persistence & Listen to Supabase Auth Changes
  useEffect(() => {
    // 1. Initial Session Check
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      }
    });

    // 2. Auth State Listener (Handles Google Redirect & Manual Login)
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      } else {
        setUser(null);
      }
    });

    // 3. Load Watch History
    const savedHistory = localStorage.getItem(STORAGE_KEYS.HISTORY);
    if (savedHistory) setHistoryIds(JSON.parse(savedHistory));

    // 4. Sync Cloud Data
    const syncCloudData = async () => {
      try {
        const cloudVideos = await getAllVideosFromCloud();
        setMovies(prev => {
          const initialIds = new Set(INITIAL_MOVIES.map(m => m.id));
          const filteredPrev = prev.filter(m => initialIds.has(m.id));
          return [...cloudVideos, ...filteredPrev];
        });
      } catch (err) {
        console.error("Sync Error:", err);
      } finally {
        setIsSyncing(false);
      }
    };

    syncCloudData();

    return () => subscription.unsubscribe();
  }, []);

  const handleLogout = async () => {
    try {
      await signOut();
      setUser(null);
    } catch (err) {
      console.error("Logout error", err);
    }
  };

  const handleUpload = (newMovie: Movie) => {
    setMovies(prev => [newMovie, ...prev]);
  };

  const handlePlay = (movie: Movie) => {
    setSelectedMovie(null);
    setPlayingMovie(movie);

    if (!historyIds.includes(movie.id)) {
      const newHistory = [movie.id, ...historyIds].slice(0, 20);
      setHistoryIds(newHistory);
      localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(newHistory));
    }
  };

  const featuredMovie = useMemo(() => {
    const scifi = movies.filter(m => m.genre === 'Sci-Fi');
    return scifi.length > 0 ? scifi[0] : movies[0];
  }, [movies]);

  const filteredMovies = useMemo(() => {
    if (!searchTerm) return movies;
    return movies.filter(m => 
      m.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
      m.genre.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [movies, searchTerm]);

  const historyMovies = useMemo(() => {
    return historyIds
      .map(id => movies.find(m => m.id === id))
      .filter((m): m is Movie => !!m);
  }, [historyIds, movies]);

  const rows = useMemo(() => {
    const userCreated = filteredMovies.filter(m => m.isUserUploaded);
    const myUploads = userCreated.filter(m => m.uploaderId === user?.id);
    const othersUploads = userCreated.filter(m => m.uploaderId !== user?.id);

    return [
      { title: 'Global Community Feed', movies: othersUploads },
      { title: 'Trending Now', movies: filteredMovies.slice(0, 10) },
      { title: 'My Cloud Uploads', movies: myUploads },
      { title: 'Continue Watching', movies: historyMovies },
      { title: 'Space & Beyond', movies: filteredMovies.filter(m => m.genre === 'Sci-Fi') },
    ];
  }, [filteredMovies, historyMovies, user]);

  return (
    <div className="relative min-h-screen pb-20 overflow-x-hidden">
      <Navbar 
        user={user}
        onUploadClick={() => user ? setShowUploadModal(true) : setShowLoginModal(true)} 
        onLoginClick={() => setShowLoginModal(true)}
        onLogout={handleLogout}
        onSearch={setSearchTerm}
      />

      {!searchTerm && (
        <Hero 
          movie={featuredMovie} 
          onInfoClick={setSelectedMovie} 
          onPlay={handlePlay}
        />
      )}

      <div className={`${searchTerm ? 'pt-24' : '-mt-32 relative z-20'} transition-all duration-500`}>
        {isSyncing && (
           <div className="px-4 md:px-12 mb-4 flex items-center space-x-2 text-xs text-blue-500 animate-pulse">
              <div className="w-2 h-2 bg-blue-500 rounded-full" />
              <span>Connecting to Supabase...</span>
           </div>
        )}

        {rows.map((row, idx) => (
          <MovieRow 
            key={row.title + idx}
            title={row.title}
            movies={row.movies}
            onMovieClick={setSelectedMovie}
          />
        ))}
      </div>

      {selectedMovie && (
        <MovieDetails movie={selectedMovie} onClose={() => setSelectedMovie(null)} onPlay={handlePlay} />
      )}

      {playingMovie && (
        <VideoPlayer movie={playingMovie} onClose={() => setPlayingMovie(null)} />
      )}

      {showUploadModal && user && (
        <UploadModal 
          user={user}
          onClose={() => setShowUploadModal(false)} 
          onUpload={handleUpload} 
        />
      )}

      {showLoginModal && (
        <LoginModal 
          onLogin={() => setShowLoginModal(false)} 
          onClose={() => setShowLoginModal(false)} 
        />
      )}

      <footer className="px-4 md:px-12 py-12 border-t border-white/5 text-gray-600 text-sm mt-20 text-center">
        <p>© 2024 GeminiStream. Powered by Supabase & Vercel.</p>
      </footer>
    </div>
  );
};

export default App;

import { Movie } from '../types.ts';
import { supabase } from './supabaseClient.ts';

/**
 * Handles Global Cloud Storage via Supabase Storage & Database
 */

export const saveVideoToCloud = async (
  movieMetadata: Partial<Movie>, 
  videoFile: File, 
  thumbnailFile: File
): Promise<Movie> => {
  // Generate unique file paths
  const timestamp = Date.now();
  const videoPath = `videos/${timestamp}-${videoFile.name.replace(/\s+/g, '_')}`;
  const thumbPath = `thumbnails/${timestamp}-${thumbnailFile.name.replace(/\s+/g, '_')}`;

  // 1. Upload Video to 'media' bucket
  const { error: videoError } = await supabase.storage
    .from('media')
    .upload(videoPath, videoFile, {
      cacheControl: '3600',
      upsert: false
    });

  if (videoError) {
    console.error("Video Upload Error:", videoError);
    throw new Error(`Video upload failed: ${videoError.message}. Make sure the 'media' bucket exists and is public.`);
  }

  // 2. Upload Thumbnail to 'media' bucket
  const { error: thumbError } = await supabase.storage
    .from('media')
    .upload(thumbPath, thumbnailFile, {
      cacheControl: '3600',
      upsert: false
    });

  if (thumbError) {
    console.error("Thumbnail Upload Error:", thumbError);
    throw new Error(`Thumbnail upload failed: ${thumbError.message}`);
  }

  // 3. Get Public URLs
  const { data: { publicUrl: videoUrl } } = supabase.storage.from('media').getPublicUrl(videoPath);
  const { data: { publicUrl: thumbnailUrl } } = supabase.storage.from('media').getPublicUrl(thumbPath);

  // 4. Insert Metadata into 'movies' table
  const { data, error: dbError } = await supabase
    .from('movies')
    .insert([{
      title: movieMetadata.title,
      description: movieMetadata.description,
      thumbnail: thumbnailUrl,
      video_url: videoUrl,
      genre: movieMetadata.genre,
      year: movieMetadata.year,
      rating: movieMetadata.rating,
      is_user_uploaded: true,
      uploader_id: movieMetadata.uploaderId,
      uploader_name: movieMetadata.uploaderName
    }])
    .select()
    .single();

  if (dbError) {
    console.error("Database Insert Error:", dbError);
    throw new Error(`Database error: ${dbError.message}`);
  }

  return {
    id: data.id,
    title: data.title,
    description: data.description,
    thumbnail: data.thumbnail,
    videoUrl: data.video_url,
    genre: data.genre,
    year: data.year,
    rating: data.rating,
    isUserUploaded: data.is_user_uploaded,
    uploaderId: data.uploader_id,
    uploaderName: data.uploader_name
  };
};

export const getAllVideosFromCloud = async (): Promise<Movie[]> => {
  const { data, error } = await supabase
    .from('movies')
    .select('*')
    .order('created_at', { ascending: false });

  if (error) {
    console.error("Supabase Fetch Error:", error);
    return [];
  }

  return (data || []).map((item: any) => ({
    id: item.id,
    title: item.title,
    description: item.description,
    thumbnail: item.thumbnail,
    videoUrl: item.video_url,
    genre: item.genre,
    year: item.year,
    rating: item.rating,
    isUserUploaded: item.is_user_uploaded,
    uploaderId: item.uploader_id,
    uploaderName: item.uploader_name
  }));
};

