import { Movie } from '../types.ts';
import { supabase } from './supabaseClient.ts';

/**
 * Cloudinary Configuration
 * For production, these should be in process.env
 * You need to create an "Unsigned Upload Preset" in Cloudinary Settings -> Upload
 */
const CLOUDINARY_CLOUD_NAME = 'gemini_stream'; // Replace with your Cloudinary Cloud Name
const CLOUDINARY_UPLOAD_PRESET = 'ml_default'; // Replace with your Unsigned Upload Preset

/**
 * Handles Global Cloud Storage via Cloudinary (for Media) & Supabase (for Metadata)
 */
export const saveVideoToCloud = async (
  movieMetadata: Partial<Movie>, 
  videoFile: File, 
  thumbnailFile: File
): Promise<Movie> => {

  // Helper to upload to Cloudinary
  const uploadToCloudinary = async (file: File, resourceType: 'video' | 'image') => {
    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', CLOUDINARY_UPLOAD_PRESET);
    formData.append('folder', 'gemini_stream_uploads');

    const response = await fetch(
      `https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD_NAME}/${resourceType}/upload`,
      {
        method: 'POST',
        body: formData,
      }
    );

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error?.message || `Cloudinary ${resourceType} upload failed`);
    }

    return await response.json();
  };

  try {
    // 1. Upload Video to Cloudinary
    // Cloudinary free tier supports up to 100MB for videos
    const videoData = await uploadToCloudinary(videoFile, 'video');
    const videoUrl = videoData.secure_url;

    // 2. Upload Thumbnail to Cloudinary
    const thumbData = await uploadToCloudinary(thumbnailFile, 'image');
    const thumbnailUrl = thumbData.secure_url;

    // 3. Insert Metadata into Supabase 'movies' table
    // We store the Cloudinary URLs in our Supabase DB
    const { data, error: dbError } = await supabase
      .from('movies')
      .insert([{
        title: movieMetadata.title,
        description: movieMetadata.description,
        thumbnail: thumbnailUrl,
        video_url: videoUrl,
        genre: movieMetadata.genre,
        year: movieMetadata.year,
        rating: movieMetadata.rating,
        is_user_uploaded: true,
        uploader_id: movieMetadata.uploaderId,
        uploader_name: movieMetadata.uploaderName
      }])
      .select()
      .single();

    if (dbError) {
      console.error("Database Insert Error:", dbError);
      throw new Error(`Database record failed: ${dbError.message}`);
    }

    return {
      id: data.id,
      title: data.title,
      description: data.description,
      thumbnail: data.thumbnail,
      videoUrl: data.video_url,
      genre: data.genre,
      year: data.year,
      rating: data.rating,
      isUserUploaded: data.is_user_uploaded,
      uploaderId: data.uploader_id,
      uploaderName: data.uploader_name
    };
  } catch (error: any) {
    console.error("Storage Service Error:", error);
    throw error;
  }
};

export const getAllVideosFromCloud = async (): Promise<Movie[]> => {
  const { data, error } = await supabase
