import { storage } from './firebaseClient.ts';
import { ref, uploadBytesResumable, getDownloadURL } from 'firebase/storage';

/**
 * Handles Global Cloud Storage via Firebase (for large media) & Supabase (for Metadata)
 */
export const saveVideoToCloud = async (
  movieMetadata: Partial<Movie>, 
  videoFile: File, 
  thumbnailFile: File,
  onProgress?: (progress: number) => void
): Promise<Movie> => {

  const uploadWithProgress = (file: File, path: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      const storageRef = ref(storage, path);
      const uploadTask = uploadBytesResumable(storageRef, file);

      uploadTask.on(
        'state_changed',
        (snapshot) => {
          const progress = (snapshot.bytesTransferred / snapshot.totalBytes) * 100;
          if (onProgress && path.includes('videos/')) {
            onProgress(progress);
          }
        },
        (error) => reject(error),
        async () => {
          const downloadURL = await getDownloadURL(uploadTask.snapshot.ref);
          resolve(downloadURL);
        }
      );
    });
  };

  try {
    const timestamp = Date.now();

    // 1. Upload Video (Higher limit: up to 5GB total bucket)
    const videoUrl = await uploadWithProgress(videoFile, `videos/${timestamp}_${videoFile.name}`);

    // 2. Upload Thumbnail
    const thumbnailUrl = await uploadWithProgress(thumbnailFile, `thumbnails/${timestamp}_${thumbnailFile.name}`);

    // 3. Insert Metadata into Supabase 'movies' table
    const { data, error: dbError } = await supabase
      .from('movies')
      .insert([{
        title: movieMetadata.title,
        description: movieMetadata.description,
        thumbnail: thumbnailUrl,
        video_url: videoUrl,
        genre: movieMetadata.genre,
        year: movieMetadata.year,
        rating: movieMetadata.rating,
        is_user_uploaded: true,
        uploader_id: movieMetadata.uploaderId,
        uploader_name: movieMetadata.uploaderName
      }])
      .select()
      .single();

    if (dbError) throw new Error(`Database record failed: ${dbError.message}`);

    return {
      id: data.id,
      title: data.title,
      description: data.description,
      thumbnail: data.thumbnail,
      videoUrl: data.video_url,
      genre: data.genre,
      year: data.year,
      rating: data.rating,
      isUserUploaded: data.is_user_uploaded,
      uploaderId: data.uploader_id,
      uploaderName: data.uploader_name
    };
  } catch (error: any) {
    console.error("Firebase Storage Error:", error);
    throw error;
  }
};

