          >
            {isUploading ? (
              <div className="flex items-center">
                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                <span>Uploading to Cloud...</span>
              </div>
            ) : (
              'Start Upload'
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

