To fix this once and for all, you need to use `ALTER TABLE` instead of just `CREATE TABLE`. If your table already exists, `CREATE TABLE IF NOT EXISTS` won't add the missing columns.

### 1. The "Universal Fix" SQL Script
Copy and run this **entire** block in your [Supabase SQL Editor](https://supabase.com/dashboard/project/diurandrwkqhefhwclyv/sql/new). It checks for each column individually and adds it if it's missing.

```sql
-- 1. Ensure the table exists
CREATE TABLE IF NOT EXISTS public.movies (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY
);

-- 2. Add each column one by one if they don't exist
DO $$ 
BEGIN 
    BEGIN ALTER TABLE public.movies ADD COLUMN created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN title text NOT NULL DEFAULT 'Untitled'; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN description text; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN thumbnail text; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN video_url text; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN genre text; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN year integer; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN rating text DEFAULT 'NR'; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN views bigint DEFAULT 0; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN is_user_uploaded boolean DEFAULT false; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN uploader_id uuid; EXCEPTION WHEN duplicate_column THEN NULL; END;
    BEGIN ALTER TABLE public.movies ADD COLUMN uploader_name text; EXCEPTION WHEN duplicate_column THEN NULL; END;
END $$;

-- 3. Reset RLS (Policies)
ALTER TABLE public.movies ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Allow public read" ON public.movies;
CREATE POLICY "Allow public read" ON public.movies FOR SELECT USING (true);
DROP POLICY IF EXISTS "Allow authenticated insert" ON public.movies;
CREATE POLICY "Allow authenticated insert" ON public.movies FOR INSERT WITH CHECK (true);

-- 4. Re-create the view increment function
CREATE OR REPLACE FUNCTION increment_views(movie_id uuid)
RETURNS void AS $$
BEGIN
    UPDATE movies
    SET views = COALESCE(views, 0) + 1
    WHERE id = movie_id;
END;
$$ LANGUAGE plpgsql;
```

### 2. Code Updates
