import React, { useState, useMemo, useEffect, useRef } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import MovieRow from './components/MovieRow.tsx';
import MovieDetails from './components/MovieDetails.tsx';
import UploadModal from './components/UploadModal.tsx';
import VideoPlayer from './components/VideoPlayer.tsx';
import LoginModal from './components/LoginModal.tsx';
import AgeDisclaimer from './components/AgeDisclaimer.tsx';
import AdBanner from './components/AdBanner.tsx';
import NativeAd from './components/NativeAd.tsx';
import { INITIAL_MOVIES } from './constants.ts';
import { Movie, User } from './types.ts';
import { getAllVideosFromCloud } from './services/storageService.ts';
import { supabase } from './services/supabaseClient.ts';
import { signOut } from './services/authService.ts';
import { Database, Wifi, WifiOff, Loader2, X } from 'lucide-react';

const STORAGE_KEYS = {
  HISTORY: 'gemini_stream_history',
  AGE_VERIFIED: 'geministream_age_verified'
};

const StickyFooterAd: React.FC = () => {
  const [visible, setVisible] = useState(true);
  if (!visible) return null;
  return (
    <div className="fixed bottom-0 left-0 w-full z-40 bg-black/80 backdrop-blur-md border-t border-white/10 animate-in slide-in-from-bottom duration-500">
      <div className="relative flex justify-center py-2 px-4">
        <button 
          onClick={() => setVisible(false)}
          className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-gray-500 hover:text-white"
        >
          <X className="w-4 h-4" />
        </button>
        <AdBanner zoneId="10802910" className="!py-0" />
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [movies, setMovies] = useState<Movie[]>(INITIAL_MOVIES);
  const [selectedMovie, setSelectedMovie] = useState<Movie | null>(null);
  const [playingMovie, setPlayingMovie] = useState<Movie | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAgeVerified, setIsAgeVerified] = useState<boolean>(true); 
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(true);
  const [isOnline, setIsOnline] = useState(true);
  const [isDeepLinking, setIsDeepLinking] = useState(false);

  const pendingVideoId = useRef<string | null>(new URLSearchParams(window.location.search).get('v'));
  const selectedMovieRef = useRef<Movie | null>(null);

  useEffect(() => {
    selectedMovieRef.current = selectedMovie;
  }, [selectedMovie]);

  useEffect(() => {
    const verified = localStorage.getItem(STORAGE_KEYS.AGE_VERIFIED);
    setIsAgeVerified(verified === 'true');

    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      }
    });

    const { data: { subscription: authSub } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      } else {
        setUser(null);
      }
    });

    const syncCloudData = async () => {
      setIsSyncing(true);
      try {
        const cloudVideos = await getAllVideosFromCloud();
        const updatedMovies = [...cloudVideos, ...INITIAL_MOVIES];
        const uniqueMovies = Array.from(new Map(updatedMovies.map(m => [m.id, m])).values());
        setMovies(uniqueMovies);
        setIsOnline(true);
      } catch (err) {
        console.error("Supabase Connection Failed:", err);
        setIsOnline(false);
      } finally {
        setIsSyncing(false);
      }
    };

    syncCloudData();

    const moviesChannel = supabase
      .channel('movies-realtime-global')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'movies' }, (payload) => {
        if (payload.eventType === 'UPDATE') {
          const updatedViews = Number(payload.new.views) || 0;
          setMovies(prev => prev.map(m => m.id === payload.new.id ? { ...m, views: updatedViews } : m));
          if (selectedMovieRef.current?.id === payload.new.id) {
            setSelectedMovie(prev => prev ? { ...prev, views: updatedViews } : null);
          }
        } else if (payload.eventType === 'INSERT') {
          const newMovie: Movie = {
            id: payload.new.id,
            title: payload.new.title,
            description: payload.new.description,
            thumbnail: payload.new.thumbnail,
            videoUrl: payload.new.video_url,
            genre: payload.new.genre,
            year: payload.new.year,
            rating: payload.new.rating,
            views: payload.new.views || 0,
            isUserUploaded: payload.new.is_user_uploaded,
            uploaderId: payload.new.uploader_id,
            uploaderName: payload.new.uploader_name
          };
          setMovies(prev => [newMovie, ...prev]);
        }
      })
      .subscribe();

    return () => {
      authSub.unsubscribe();
      supabase.removeChannel(moviesChannel);
    };
  }, []);

  useEffect(() => {
    const processDeepLink = () => {
      const params = new URLSearchParams(window.location.search);
      const videoId = params.get('v');
      const autoplay = params.get('autoplay') === 'true';

      if (videoId) {
        const target = movies.find(m => m.id === videoId);
        if (target) {
          setIsDeepLinking(false);
          pendingVideoId.current = null;
          if (autoplay) {
            setPlayingMovie(target);
            setSelectedMovie(null);
          } else {
            setSelectedMovie(target);
            setPlayingMovie(null);
          }
        } else {
          setIsDeepLinking(true);
        }
      } else {
        setIsDeepLinking(false);
      }
    };

    processDeepLink();
    window.addEventListener('popstate', processDeepLink);
    return () => window.removeEventListener('popstate', processDeepLink);
  }, [movies]);

  const handleLogout = async () => {
    try {
      await signOut();
      setUser(null);
    } catch (err) {
      console.error("Logout error", err);
    }
  };

  const handlePlay = (movie: Movie) => {
    setSelectedMovie(null);
    setPlayingMovie(movie);
  };

  const filteredMovies = useMemo(() => {
    const term = searchTerm.toLowerCase();
    if (!term) return movies;
    return movies.filter(m => 
      m.title.toLowerCase().includes(term) || 
      m.genre.toLowerCase().includes(term) ||
      (m.uploaderName && m.uploaderName.toLowerCase().includes(term))
    );
  }, [movies, searchTerm]);

  const rows = useMemo(() => {
    return [
      { title: 'Trending', movies: [...filteredMovies].sort((a,b) => b.views - a.views).slice(0, 10) },
      { title: 'Insta post', movies: filteredMovies.filter(m => m.genre === 'Insta post') },
      { title: 'Viral', movies: filteredMovies.filter(m => m.genre === 'Viral') },
      { title: 'Onlyfans', movies: filteredMovies.filter(m => m.genre === 'Onlyfans') },
      { title: 'All Content', movies: filteredMovies },
    ];
  }, [filteredMovies]);

  return (
    <div className={`relative min-h-screen pb-20 bg-[#141414] ${!isAgeVerified ? 'max-h-screen overflow-hidden' : ''}`}>
      {!isAgeVerified && <AgeDisclaimer onVerify={() => {
        localStorage.setItem(STORAGE_KEYS.AGE_VERIFIED, 'true');
        setIsAgeVerified(true);
      }} />}

      <Navbar 
        user={user}
        onUploadClick={() => user ? setShowUploadModal(true) : setShowLoginModal(true)} 
        onLoginClick={() => setShowLoginModal(true)}
        onLogout={handleLogout}
        onSearch={setSearchTerm}
      />

      {isDeepLinking && isSyncing && (
        <div className="fixed inset-0 z-[80] bg-black/90 flex flex-col items-center justify-center space-y-4">
           <Loader2 className="w-12 h-12 text-red-600 animate-spin" />
           <p className="text-white font-bold uppercase tracking-widest text-sm animate-pulse">Fetching shared content...</p>
        </div>
      )}

      {!searchTerm && movies.length > 0 && (
        <Hero 
          movie={movies[0]} 
          onInfoClick={setSelectedMovie} 
          onPlay={handlePlay}
        />
      )}

      <div className={`${searchTerm ? 'pt-24' : '-mt-32 relative z-20'} transition-all duration-500`}>
        <div className="px-4 md:px-12 mb-6 flex items-center justify-between">
          <div className="flex items-center space-x-3">
             <div className={`p-1.5 rounded-lg ${isOnline ? 'bg-green-600/10 text-green-500' : 'bg-red-600/10 text-red-500'}`}>
                {isOnline ? <Wifi className="w-4 h-4" /> : <WifiOff className="w-4 h-4" />}
             </div>
             <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-tighter text-gray-500">Supabase Project</span>
                <span className="text-xs font-bold text-white leading-none">Stream (diurandrwkqhe...)</span>
             </div>
          </div>

          {isSyncing && (
            <div className="flex items-center space-x-2 text-[10px] font-bold text-orange-500 uppercase tracking-widest animate-pulse">
               <Database className="w-3 h-3" />
               <span>Syncing Realtime...</span>
            </div>
          )}
        </div>

        {rows.map((row, idx) => (
          <React.Fragment key={row.title + idx}>
            <MovieRow 
              title={row.title}
              movies={row.movies}
              onMovieClick={setSelectedMovie}
            />
            {/* IN-FEED ADS: Balanced distribution */}
            {idx === 0 && <AdBanner zoneId="10802910" className="opacity-80" />}
            {idx === 1 && <NativeAd />}
            {idx === 2 && <AdBanner zoneId="10802946" />}
            {idx === 3 && <NativeAd />}
          </React.Fragment>
        ))}
      </div>

      {selectedMovie && (
        <MovieDetails movie={selectedMovie} onClose={() => setSelectedMovie(null)} onPlay={handlePlay} />
      )}

      {playingMovie && (
        <VideoPlayer movie={playingMovie} onClose={() => setPlayingMovie(null)} />
      )}

      {showUploadModal && user && (
        <UploadModal 
          user={user}
          onClose={() => setShowUploadModal(false)} 
          onUpload={(m) => setMovies(prev => [m, ...prev])} 
        />
      )}

      {showLoginModal && (
        <LoginModal 
          onLogin={() => setShowLoginModal(false)} 
          onClose={() => setShowLoginModal(false)} 
        />
      )}

      <div className="px-4 md:px-12 mt-12 mb-20">
        <AdBanner zoneId="10802910" />
      </div>

      <footer className="px-4 md:px-12 py-16 border-t border-white/5 text-gray-600 text-sm mt-20 text-center pb-32">
        <div className="flex flex-col items-center space-y-4">
          <div className="flex items-center space-x-2 bg-white/5 px-4 py-2 rounded-full border border-white/10">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-ping" />
            <span className="text-[10px] font-black uppercase tracking-widest text-white">Live Backend Linked</span>
          </div>
          <p className="max-w-md mx-auto text-xs opacity-50">
            All user data, uploads, and view statistics are synchronized in real-time using Supabase.
          </p>
          <p>© 2024 GeminiStream Platform.</p>
        </div>
      </footer>

      {/* STICKY AD: Ensures ad visibility on all views */}
      <StickyFooterAd />
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { X, ArrowLeft, Volume2, VolumeX, AlertCircle, Loader2 } from 'lucide-react';
import { Movie } from '../types.ts';
import { incrementMovieView } from '../services/storageService.ts';

// Declare types for global libraries included in index.html
declare var videojs: any;

interface VideoPlayerProps {
  movie: Movie;
  onClose: () => void;
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ movie, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const playerRef = useRef<any>(null);
  const adTimeoutRef = useRef<number | null>(null);
  const [isMuted, setIsMuted] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isAdPlaying, setIsAdPlaying] = useState(false);
  const [adLoading, setAdLoading] = useState(true);

  useEffect(() => {
    if (!videoRef.current) return;

    // 1. Initialize Video.js with standard Netflix-like settings
    const player = videojs(videoRef.current, {
      autoplay: true,
      controls: true,
      muted: true,
      responsive: true,
      fluid: true,
      playbackRates: [0.5, 1, 1.5, 2],
      poster: movie.thumbnail,
      sources: movie.videoUrl ? [{
        src: movie.videoUrl,
        type: 'video/mp4'
      }] : []
    });

    playerRef.current = player;

    // Critical fix: This function forces the UI to return to content mode
    const forceContentPlay = () => {
      console.log('IMA: Forcing content playback and clearing UI block.');
      if (adTimeoutRef.current) {
        clearTimeout(adTimeoutRef.current);
        adTimeoutRef.current = null;
      }

      setIsAdPlaying(false);
      setAdLoading(false);

      if (player) {
        // Explicitly strip classes that hide controls
        player.removeClass('vjs-ad-playing');
        player.removeClass('vjs-ad-loading');
        player.removeClass('vjs-ad-active');

        // Attempt to play content
        const playPromise = player.play();
        if (playPromise !== undefined) {
          playPromise.catch((err: any) => {
            console.warn('Playback resume handled:', err);
          });
        }
      }
    };

    // 2. Setup IMA with the Adcash/Onclickalgo VAST tag
    player.ready(() => {
      if (player.ima) {
        const imaOptions = {
          id: 'my-video',
          adTagUrl: 'https://onclickalgo.com/video/select.php?r=10802842',
          showCountdown: true,
          debug: false,
          adWillAutoPlay: true,
          adsResponseTimeout: 5000 // Faster timeout for better UX
        };

        try {
          player.ima(imaOptions);

          // Success Events
          player.on('ads-ad-started', () => {
            if (adTimeoutRef.current) clearTimeout(adTimeoutRef.current);
            setIsAdPlaying(true);
            setAdLoading(false);
          });

          // Completion Events
          player.on('ads-ad-ended', forceContentPlay);
          player.on('ads-all-ads-completed', forceContentPlay);

          // Error/Blocker handling - ensures buttons don't stay "stuck"
          player.on('ads-error', (event: any) => {
            console.warn('IMA Ads Error:', event.error);
            forceContentPlay();
          });

          player.on('aderror', forceContentPlay);
          player.on('contentresumerequested', forceContentPlay);

          // Pre-roll Request Trigger on User Interaction
          const requestAdsOnPlay = () => {
            player.ima.initializeAdDisplayContainer();
            player.ima.requestAds();

            // Fail-safe: If ad hasn't started in 6 seconds, just play the movie
            adTimeoutRef.current = window.setTimeout(() => {
              if (adLoading || isAdPlaying === false) {
                console.warn('Ad Request Hang - Bypassing to movie.');
                forceContentPlay();
              }
            }, 6000);

            player.off('play', requestAdsOnPlay);
          };
          player.on('play', requestAdsOnPlay);

        } catch (e) {
          console.error("IMA setup failure:", e);
          forceContentPlay();
        }
      } else {
        forceContentPlay();
      }
    });

    // 3. Track View Analytics
    player.on('contentplay', () => {
      if (movie.id) incrementMovieView(movie.id);
    });

    player.on('error', () => {
      setError("Stream could not be initialized.");
      setAdLoading(false);
    });

    return () => {
      if (adTimeoutRef.current) clearTimeout(adTimeoutRef.current);
      if (playerRef.current) {
        playerRef.current.dispose();
      }
    };
  }, [movie]);

  const toggleMute = () => {
    if (playerRef.current) {
      const newMuted = !isMuted;
      playerRef.current.muted(newMuted);
      setIsMuted(newMuted);
    }
  };

  return (
    <div className="fixed inset-0 z-[200] bg-black flex flex-col items-center justify-center animate-in fade-in duration-500 overflow-hidden">
      {/* Top Header Overlay */}
      <div className="absolute top-0 left-0 w-full p-4 md:p-8 flex items-center justify-between z-[220] bg-gradient-to-b from-black/90 to-transparent pointer-events-none">
        <button 
          onClick={onClose}
          className="flex items-center text-white hover:text-gray-300 transition-colors group pointer-events-auto"
        >
          <ArrowLeft className="w-8 h-8 mr-2 group-hover:-translate-x-1 transition-transform" />
          <span className="text-xl font-bold hidden md:inline tracking-tight">Back</span>
        </button>

        <div className="text-center">
          <h2 className="text-lg md:text-2xl font-bold truncate max-w-xs md:max-w-md uppercase tracking-tighter">
            {isAdPlaying ? 'Advertisement' : movie.title}
          </h2>
          {(isAdPlaying || adLoading) && (
            <div className="flex items-center justify-center space-x-2">
              <span className="text-[10px] bg-red-600 px-2 py-0.5 rounded font-black text-white uppercase tracking-widest animate-pulse">
                {adLoading ? 'Authenticating...' : 'Sponsored Content'}
              </span>
            </div>
          )}
        </div>

        <button 
          onClick={onClose}
          className="p-2 hover:bg-white/10 rounded-full transition-colors pointer-events-auto"
        >
          <X className="w-8 h-8" />
        </button>
      </div>

      <div className="w-full h-full flex items-center justify-center bg-black relative group">
        {adLoading && !error && (
          <div className="absolute inset-0 z-[215] flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm">
            <Loader2 className="w-12 h-12 text-red-600 animate-spin mb-4" />
            <p className="text-sm font-bold uppercase tracking-widest text-gray-400">Negotiating Stream...</p>
          </div>
        )}

        {error ? (
          <div className="text-center space-y-6 animate-in zoom-in duration-300 px-6">
            <div className="w-20 h-20 bg-red-600/10 border-2 border-red-600 rounded-full flex items-center justify-center mx-auto mb-6">
              <AlertCircle className="w-10 h-10 text-red-600" />
            </div>
            <h3 className="text-2xl font-black uppercase tracking-tighter text-white">Playback Error</h3>
            <p className="text-gray-400 max-w-md mx-auto leading-relaxed text-sm">
              We couldn't initialize the secure stream. Please check your internet and disable any ad-blockers to view this content.
            </p>
            <button 
              onClick={onClose} 
              className="bg-white text-black px-10 py-3 rounded-full font-black uppercase tracking-widest hover:bg-gray-200 transition"
            >
              Exit Player
            </button>
          </div>
        ) : (
          <div data-vjs-player className="w-full h-full">
            <video 
              id="my-video"
              ref={videoRef} 
              className="video-js vjs-big-play-centered vjs-theme-netflix" 
              playsInline
            />
          </div>
        )}

        {/* Custom Mute Control */}
        {!error && !adLoading && !isAdPlaying && (
          <button 
            onClick={toggleMute}
            className="absolute bottom-10 left-10 z-[210] p-4 bg-black/40 hover:bg-black/60 rounded-full border border-white/10 text-white transition-all opacity-0 group-hover:opacity-100"
          >
            {isMuted ? <VolumeX className="w-6 h-6" /> : <Volume2 className="w-6 h-6" />}
          </button>
        )}
      </div>

      <style>{`
        /* FIX: Ensure ad container doesn't steal clicks when inactive */
        .vjs-ima-ad-container {
          z-index: 215 !important;
          pointer-events: none !important;
        }
        /* Only allow clicks on ad container during active playback */
        .vjs-ad-playing .vjs-ima-ad-container,
        .vjs-ad-active .vjs-ima-ad-container {
          pointer-events: auto !important;
        }

