const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [movies, setMovies] = useState<Movie[]>(INITIAL_MOVIES);
  const [selectedMovie, setSelectedMovie] = useState<Movie | null>(null);
  const [playingMovie, setPlayingMovie] = useState<Movie | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAgeVerified, setIsAgeVerified] = useState<boolean>(true); 
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(true);
  const [isOnline, setIsOnline] = useState(true);
  const [isDeepLinking, setIsDeepLinking] = useState(false);

  const pendingVideoId = useRef<string | null>(new URLSearchParams(window.location.search).get('v'));
  const selectedMovieRef = useRef<Movie | null>(null);

  useEffect(() => {
    selectedMovieRef.current = selectedMovie;
  }, [selectedMovie]);

  useEffect(() => {
    const verified = localStorage.getItem(STORAGE_KEYS.AGE_VERIFIED);
    setIsAgeVerified(verified === 'true');

    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      }
    });

    const { data: { subscription: authSub } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      } else {
        setUser(null);
      }
    });

    const syncCloudData = async () => {
      setIsSyncing(true);
      try {
        const cloudVideos = await getAllVideosFromCloud();
        const updatedMovies = [...cloudVideos, ...INITIAL_MOVIES];
        const uniqueMovies = Array.from(new Map(updatedMovies.map(m => [m.id, m])).values());
        setMovies(uniqueMovies);
        setIsOnline(true);
      } catch (err) {
        console.error("Supabase Connection Failed:", err);
        setIsOnline(false);
      } finally {
        setIsSyncing(false);
      }
    };

    syncCloudData();

    const moviesChannel = supabase
      .channel('movies-realtime-global')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'movies' }, (payload) => {
        if (payload.eventType === 'UPDATE') {
          const updatedViews = Number(payload.new.views) || 0;
          setMovies(prev => prev.map(m => m.id === payload.new.id ? { ...m, views: updatedViews } : m));
          if (selectedMovieRef.current?.id === payload.new.id) {
            setSelectedMovie(prev => prev ? { ...prev, views: updatedViews } : null);
          }
        } else if (payload.eventType === 'INSERT') {
          const newMovie: Movie = {
            id: payload.new.id,
            title: payload.new.title,
            description: payload.new.description,
            thumbnail: payload.new.thumbnail,
            videoUrl: payload.new.video_url,
            genre: payload.new.genre,
            year: payload.new.year,
            rating: payload.new.rating,
            views: payload.new.views || 0,
            isUserUploaded: payload.new.is_user_uploaded,
            uploaderId: payload.new.uploader_id,
            uploaderName: payload.new.uploader_name
          };
          setMovies(prev => [newMovie, ...prev]);
        }
      })
      .subscribe();

    return () => {
      authSub.unsubscribe();
      supabase.removeChannel(moviesChannel);
    };
  }, []);

  useEffect(() => {
    const processDeepLink = () => {
      const params = new URLSearchParams(window.location.search);
      const videoId = params.get('v');
      const autoplay = params.get('autoplay') === 'true';

      if (videoId) {
        const target = movies.find(m => m.id === videoId);
        if (target) {
          setIsDeepLinking(false);
          pendingVideoId.current = null;
          if (autoplay) {
            setPlayingMovie(target);
            setSelectedMovie(null);
          } else {
            setSelectedMovie(target);
            setPlayingMovie(null);
          }
        } else {
          setIsDeepLinking(true);
        }
      } else {
        setIsDeepLinking(false);
      }
    };

    processDeepLink();
    window.addEventListener('popstate', processDeepLink);
    return () => window.removeEventListener('popstate', processDeepLink);
  }, [movies]);

  const handleLogout = async () => {
    try {
      await signOut();
      setUser(null);
    } catch (err) {
      console.error("Logout error", err);
    }
  };

  const handlePlay = (movie: Movie) => {
    setSelectedMovie(null);
    setPlayingMovie(movie);
  };

  const filteredMovies = useMemo(() => {
    const term = searchTerm.toLowerCase();
    if (!term) return movies;
    return movies.filter(m => 
      m.title.toLowerCase().includes(term) || 
      m.genre.toLowerCase().includes(term) ||
      (m.uploaderName && m.uploaderName.toLowerCase().includes(term))
    );
  }, [movies, searchTerm]);

  const rows = useMemo(() => {
    const userUploads = filteredMovies.filter(m => m.isUserUploaded === true);

    return [
      { 
        title: 'Trending Community Uploads', 
        movies: userUploads.sort((a,b) => b.views - a.views).slice(0, 15) 
      },
      { title: 'Insta post', movies: filteredMovies.filter(m => m.genre === 'Insta post') },
      { title: 'Viral Highlights', movies: filteredMovies.filter(m => m.genre === 'Viral') },
      { title: 'Onlyfans Exclusives', movies: filteredMovies.filter(m => m.genre === 'Onlyfans') },
      { title: 'Full Library', movies: filteredMovies },
    ];
  }, [filteredMovies]);

  return (
    <div className={`relative min-h-screen pb-20 bg-[#141414] ${!isAgeVerified ? 'max-h-screen overflow-hidden' : ''}`}>
      {!isAgeVerified && <AgeDisclaimer onVerify={() => {
        localStorage.setItem(STORAGE_KEYS.AGE_VERIFIED, 'true');
        setIsAgeVerified(true);
      }} />}

      <Navbar 
        user={user}
        onUploadClick={() => user ? setShowUploadModal(true) : setShowLoginModal(true)} 
        onLoginClick={() => setShowLoginModal(true)}
        onLogout={handleLogout}
        onSearch={setSearchTerm}
      />

      {isDeepLinking && isSyncing && (
        <div className="fixed inset-0 z-[80] bg-black/90 flex flex-col items-center justify-center space-y-4">
           <Loader2 className="w-12 h-12 text-red-600 animate-spin" />
           <p className="text-white font-bold uppercase tracking-widest text-sm animate-pulse">Fetching shared content...</p>
        </div>
      )}

      {!searchTerm && movies.length > 0 && (
        <Hero 
          movie={movies[0]} 
          onInfoClick={setSelectedMovie} 
          onPlay={handlePlay}
        />
      )}

      <div className={`${searchTerm ? 'pt-24' : '-mt-32 relative z-20'} transition-all duration-500`}>
        <div className="px-4 md:px-12 mb-6 flex items-center justify-between">
          <div className="flex items-center space-x-3">
             <div className={`p-1.5 rounded-lg ${isOnline ? 'bg-green-600/10 text-green-500' : 'bg-red-600/10 text-red-500'}`}>
                {isOnline ? <Wifi className="w-4 h-4" /> : <WifiOff className="w-4 h-4" />}
             </div>
             <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-tighter text-gray-500">Supabase Project</span>
                <span className="text-xs font-bold text-white leading-none">Stream (diurandrwkqhe...)</span>
             </div>
          </div>

          {isSyncing && (
            <div className="flex items-center space-x-2 text-[10px] font-bold text-orange-500 uppercase tracking-widest animate-pulse">
               <Database className="w-3 h-3" />
               <span>Syncing Realtime...</span>
            </div>
          )}
        </div>

        {rows.map((row, idx) => (
          <React.Fragment key={row.title + idx}>
            <MovieRow 
              title={row.title}
              movies={row.movies}
              onMovieClick={setSelectedMovie}
              onPlay={handlePlay}
            />
            {/* IN-FEED ADS: Balanced distribution */}
            {idx === 0 && <AdBanner zoneId="10802910" className="opacity-80" />}
            {idx === 1 && <NativeAd />}
            {idx === 2 && <AdBanner zoneId="10802946" />}
            {idx === 3 && <NativeAd />}
          </React.Fragment>
        ))}
      </div>

      {selectedMovie && (
        <MovieDetails 
          movie={selectedMovie} 
          allMovies={movies}
          onClose={() => setSelectedMovie(null)} 
          onPlay={handlePlay} 
          onMovieSelect={setSelectedMovie}
        />
      )}

      {playingMovie && (
        <VideoPlayer movie={playingMovie} onClose={() => setPlayingMovie(null)} />
      )}

      {showUploadModal && user && (
        <UploadModal 
          user={user}
          onClose={() => setShowUploadModal(false)} 
          onUpload={(m) => setMovies(prev => [m, ...prev])} 
        />
      )}

      {showLoginModal && (
        <LoginModal 
          onLogin={() => setShowLoginModal(false)} 
          onClose={() => setShowLoginModal(false)} 
        />
      )}

      <div className="px-4 md:px-12 mt-12 mb-20">
        <AdBanner zoneId="10802910" />
      </div>

      <footer className="px-4 md:px-12 py-16 border-t border-white/5 text-gray-600 text-sm mt-20 text-center pb-32">
        <div className="flex flex-col items-center space-y-4">
          <div className="flex items-center space-x-2 bg-white/5 px-4 py-2 rounded-full border border-white/10">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-ping" />
            <span className="text-[10px] font-black uppercase tracking-widest text-white">Live Backend Linked</span>
          </div>
          <p className="max-w-md mx-auto text-xs opacity-50">
            All user data, uploads, and view statistics are synchronized in real-time using Supabase.
          </p>
          <p>© 2024 GeminiStream Platform.</p>
        </div>
      </footer>

      <StickyFooterAd />
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Share2, Check, Eye, Play } from 'lucide-react';
import { Movie } from '../types.ts';

interface MovieRowProps {
  title: string;
  movies: Movie[];
  onMovieClick: (movie: Movie) => void;
  onPlay: (movie: Movie) => void;
}

const formatViews = (views: number) => {
  if (views >= 1000000) return (views / 1000000).toFixed(1) + 'M';
  if (views >= 1000) return (views / 1000).toFixed(1) + 'K';
  return views.toString();
};

const MovieRow: React.FC<MovieRowProps> = ({ title, movies, onMovieClick, onPlay }) => {
  const rowRef = useRef<HTMLDivElement>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const scroll = (direction: 'left' | 'right') => {
    if (rowRef.current) {
      const { scrollLeft, clientWidth } = rowRef.current;
      const scrollTo = direction === 'left' ? scrollLeft - clientWidth : scrollLeft + clientWidth;
      rowRef.current.scrollTo({ left: scrollTo, behavior: 'smooth' });
    }
  };

  const handleShare = async (e: React.MouseEvent, movie: Movie) => {
    e.stopPropagation();
    const shareUrl = `${window.location.origin}?v=${movie.id}`;
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopiedId(movie.id);
      setTimeout(() => setCopiedId(null), 2000);
    } catch (err) {
      console.error('Failed to copy link:', err);
    }
  };

  const handlePlayClick = (e: React.MouseEvent, movie: Movie) => {
    e.stopPropagation();
    onPlay(movie);
  };

  if (movies.length === 0) return null;

  return (
    <div className="space-y-4 mb-8">
      <h3 className="text-xl md:text-2xl font-bold px-4 md:px-12 text-gray-100 uppercase tracking-tighter">{title}</h3>
      <div className="group relative flex items-center">
        <button 
          onClick={() => scroll('left')}
          className="absolute left-0 z-30 p-2 bg-black/50 h-full opacity-0 group-hover:opacity-100 transition duration-300 hover:scale-125 md:px-4"
        >
          <ChevronLeft className="w-8 h-8" />
        </button>

        <div 
          ref={rowRef}
          className="row-container flex space-x-2 md:space-x-4 overflow-x-auto px-4 md:px-12 scroll-smooth py-4"
        >
          {movies.map((movie) => (
            <div 
              key={movie.id}
              onClick={() => onMovieClick(movie)}
              className="relative flex-none w-40 h-24 md:w-64 md:h-36 cursor-pointer transition duration-300 hover:scale-110 hover:z-20 rounded-md overflow-hidden bg-zinc-900 group/card shadow-lg hover:shadow-red-600/20"
            >
              <img 
                src={movie.thumbnail} 
                alt={movie.title} 
                className="w-full h-full object-cover brightness-[0.85] group-hover/card:brightness-50 transition-all duration-300"
              />

              {/* Central Play Button on Hover */}
              <button 
                onClick={(e) => handlePlayClick(e, movie)}
                className="absolute inset-0 m-auto w-10 h-10 md:w-14 md:h-14 bg-red-600 rounded-full flex items-center justify-center opacity-0 group-hover/card:opacity-100 scale-50 group-hover/card:scale-100 transition-all duration-300 shadow-[0_0_20px_rgba(229,9,20,0.6)] z-40 hover:scale-110 active:scale-90"
              >
                <Play className="w-5 h-5 md:w-7 md:h-7 text-white fill-white ml-1" />
              </button>

              <button 
                onClick={(e) => handleShare(e, movie)}
                className="absolute top-2 right-2 z-30 p-1.5 bg-black/60 rounded-full border border-white/10 opacity-0 group-hover/card:opacity-100 transition-opacity hover:bg-red-600 hover:border-red-600"
              >
                {copiedId === movie.id ? <Check className="w-3 h-3 md:w-4 md:h-4 text-white" /> : <Share2 className="w-3 h-3 md:w-4 md:h-4 text-white" />}
              </button>

              <div className="absolute top-2 left-2 z-30 flex items-center bg-black/40 backdrop-blur-sm px-1.5 py-0.5 rounded text-[10px] font-bold text-white opacity-0 group-hover/card:opacity-100 transition-opacity">
                <Eye className="w-3 h-3 mr-1 text-red-500" />
                <span className="tabular-nums">
                  {formatViews(movie.views)}
                </span>
              </div>

              {copiedId === movie.id && (
                <div className="absolute top-10 right-2 z-40 bg-green-600 text-white text-[8px] font-bold px-1.5 py-0.5 rounded shadow-lg animate-in fade-in slide-in-from-top-1 uppercase tracking-tighter">
                  Copied!
                </div>
              )}

              <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black via-black/60 to-transparent opacity-0 group-hover/card:opacity-100 transition-opacity p-2 md:p-4">
                 <p className="text-xs md:text-sm font-bold text-white truncate pr-6">{movie.title}</p>
                 <div className="flex items-center space-x-2 text-[8px] md:text-[10px] text-green-400 font-bold mt-1">
                    <span>{movie.rating}</span>
                    <span>{movie.year}</span>
                    {movie.isUserUploaded && <span className="text-orange-500 border border-orange-500/30 px-1 rounded-sm uppercase tracking-tighter text-[7px] md:text-[8px]">User Choice</span>}
                 </div>
              </div>
            </div>
          ))}
        </div>

        <button 
          onClick={() => scroll('right')}
          className="absolute right-0 z-30 p-2 bg-black/50 h-full opacity-0 group-hover:opacity-100 transition duration-300 hover:scale-125 md:px-4"
        >
          <ChevronRight className="w-8 h-8" />
        </button>
      </div>
    </div>
  );
};

export default MovieRow;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { X, Play, Plus, ThumbsUp, Sparkles, User, Share2, Check, Eye, Zap, TrendingUp } from 'lucide-react';
import { Movie } from '../types.ts';
import { getMovieAIInsight } from '../services/geminiService.ts';
import AdBanner from './AdBanner.tsx';

interface MovieDetailsProps {
  movie: Movie;
  allMovies: Movie[];
  onClose: () => void;
  onPlay: (movie: Movie) => void;
  onMovieSelect: (movie: Movie) => void;
}

const formatViews = (views: number) => {
  if (views >= 1000000) return (views / 1000000).toFixed(1) + 'M';
  if (views >= 1000) return (views / 1000).toFixed(1) + 'K';
  return views.toString();
};

const MovieDetails: React.FC<MovieDetailsProps> = ({ movie, allMovies, onClose, onPlay, onMovieSelect }) => {
  const [aiInsight, setAiInsight] = useState<string>('Summoning Gemini intelligence...');
  const [loadingAi, setLoadingAi] = useState(true);
  const [copied, setCopied] = useState<'info' | 'play' | null>(null);
  const [viewPulse, setViewPulse] = useState(false);
  const prevViews = useRef(movie.views);

  useEffect(() => {
    const fetchAI = async () => {
      setLoadingAi(true);
      const insight = await getMovieAIInsight(movie.title);
      setAiInsight(insight);
      setLoadingAi(false);
    };
    fetchAI();

    const modal = document.querySelector('.modal-scroll-container');
    if (modal) modal.scrollTo({ top: 0, behavior: 'smooth' });
  }, [movie.id]);

  useEffect(() => {
    if (movie.views !== prevViews.current) {
      setViewPulse(true);
      const timer = setTimeout(() => setViewPulse(false), 1000);
      prevViews.current = movie.views;
      return () => clearTimeout(timer);
    }
  }, [movie.views]);

  const suggestions = useMemo(() => {
    return allMovies
      .filter(m => m.isUserUploaded === true && m.id !== movie.id)
      .sort((a, b) => b.views - a.views)
      .slice(0, 10);
  }, [allMovies, movie.id]);

  const handleShare = async (directPlay: boolean = false) => {
    const shareUrl = `${window.location.origin}?v=${movie.id}${directPlay ? '&autoplay=true' : ''}`;
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(directPlay ? 'play' : 'info');
      setTimeout(() => setCopied(null), 2000);
    } catch (err) {
      console.error('Failed to copy link:', err);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm overflow-y-auto modal-scroll-container">
      <div className="relative bg-[#181818] w-full max-w-4xl my-8 rounded-xl overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-300">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 z-50 bg-black/60 p-2 rounded-full hover:bg-black/80 transition"
        >
          <X className="w-6 h-6" />
        </button>

        <div className="relative h-64 md:h-96">
          <img 
            src={movie.thumbnail} 
            alt={movie.title} 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-[#181818] to-transparent" />

          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
             <button 
              onClick={() => onPlay(movie)}
              className="pointer-events-auto bg-red-600/90 text-white w-16 h-16 md:w-24 md:h-24 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(229,9,20,0.5)] hover:scale-110 active:scale-95 transition-transform duration-300 hover:bg-red-600"
             >
                <Play className="w-8 h-8 md:w-12 md:h-12 fill-white ml-1.5" />
             </button>
          </div>

          <div className="absolute bottom-8 left-8 right-8">
            <h2 className="text-3xl md:text-5xl font-black mb-4 tracking-tighter drop-shadow-xl">{movie.title}</h2>
            <div className="flex flex-wrap gap-4 items-center">
              <button 
                onClick={() => onPlay(movie)}
                className="bg-white text-black px-10 py-3 rounded flex items-center font-black uppercase tracking-widest hover:bg-gray-200 transition active:scale-95 shadow-lg"
              >
                <Play className="w-5 h-5 mr-2 fill-black" /> Play Now
              </button>

              <div className="hidden sm:block h-10 w-px bg-white/10 mx-2" />

              <div className="flex space-x-2">
                <button 
                  onClick={() => handleShare(false)}
                  className={`p-3 rounded-full border-2 transition flex items-center justify-center relative ${copied === 'info' ? 'bg-green-600 border-green-600 text-white' : 'bg-gray-500/50 border-white/20 hover:border-white text-white'}`}
                  title="Share Info Page"
                >
                  {copied === 'info' ? <Check className="w-6 h-6" /> : <Share2 className="w-6 h-6" />}
                  {copied === 'info' && (
                    <span className="absolute -top-10 left-1/2 -translate-x-1/2 bg-green-600 text-white text-[10px] font-bold px-2 py-1 rounded shadow-lg animate-in fade-in slide-in-from-bottom-1 uppercase tracking-widest whitespace-nowrap">
                      Link Copied!
                    </span>
                  )}
                </button>

                <button 
                  onClick={() => handleShare(true)}
                  className={`p-3 rounded-full border-2 transition flex items-center justify-center relative ${copied === 'play' ? 'bg-orange-600 border-orange-600 text-white' : 'bg-gray-500/50 border-white/20 hover:border-orange-500 text-white'}`}
                  title="Share Direct Play Link"
                >
                  {copied === 'play' ? <Check className="w-6 h-6" /> : <Zap className="w-6 h-6" />}
                </button>

                <button className="bg-gray-500/50 p-3 rounded-full border-2 border-white/20 hover:border-white transition text-white">
                  <ThumbsUp className="w-6 h-6" />
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="p-8 pb-4">
           <AdBanner zoneId="10802946" className="mb-6" />

           <div className="grid md:grid-cols-3 gap-8">
            <div className="md:col-span-2 space-y-6">
              <div className="flex flex-wrap items-center gap-3 text-sm font-semibold">
                <span className="text-green-500">98% Match</span>
                <span className="border border-gray-500 px-1 text-xs">{movie.rating}</span>
                <span>{movie.year}</span>
                <span className={`flex items-center transition-all duration-300 ${viewPulse ? 'text-red-500 scale-110 font-black' : 'text-gray-400'}`}>
                  <Eye className={`w-4 h-4 mr-1 ${viewPulse ? 'animate-bounce' : ''}`} />
                  {formatViews(movie.views)} views
                </span>
                <span className="border border-gray-500 px-1 text-[10px] rounded">HD</span>
              </div>

              {movie.uploaderName && (
                <div className="flex items-center space-x-2 text-sm text-gray-400 bg-white/5 w-fit px-3 py-1 rounded-full border border-white/10">
                  <User className="w-4 h-4" />
                  <span>Uploaded by <span className="text-white font-bold">{movie.uploaderName}</span></span>
                </div>
              )}

              <p className="text-gray-200 text-lg leading-relaxed">
                {movie.description}
              </p>

              <div className="bg-indigo-950/30 border border-indigo-500/30 p-6 rounded-xl space-y-3 relative overflow-hidden group">
                 <div className="flex items-center space-x-2 text-indigo-400 font-bold uppercase text-xs tracking-widest">
                    <Sparkles className="w-4 h-4" />
                    <span>Gemini AI Discovery</span>
                 </div>
                 <p className={`italic text-indigo-100 ${loadingAi ? 'animate-pulse' : ''}`}>
                   "{aiInsight}"
                 </p>
                 <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-500/5 blur-[60px] rounded-full" />
              </div>
            </div>

            <div className="space-y-4 text-sm">
              <div className="flex justify-between border-b border-white/5 pb-2">
                <span className="text-gray-500">Genre:</span> <span className="text-gray-200">{movie.genre}</span>
              </div>
              <div className="flex justify-between border-b border-white/5 pb-2">
                <span className="text-gray-500">Category:</span> <span className="text-gray-200">{movie.isUserUploaded ? 'Community Content' : 'Premium Movie'}</span>
              </div>
              <div className="pt-4">
