    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validations
    if (!isEditMode) {
      if (uploadType === 'file' && (!videoFile || !title)) {
        setUploadError("Please provide a title and select a video file.");
        return;
      }
      if (uploadType === 'link' && (!videoUrl || !title)) {
        setUploadError("Please provide a title and a valid video link.");
        return;
      }
    }

    setIsUploading(true);
    setUploadError(null);
    setUploadProgress(0);

    try {
      const metadata: Partial<Movie> = {
        id: movieToEdit?.id,
        title,
        description,
        genre,
        year: movieToEdit?.year || new Date().getFullYear(),
        rating: movieToEdit?.rating || 'NR',
        isUserUploaded: true,
        uploaderId: user.id,
        uploaderName: user.name,
        videoUrl: uploadType === 'link' ? videoUrl : (movieToEdit?.videoUrl || undefined),
        thumbnail: thumbnailUrl || (movieToEdit?.thumbnail || undefined)
      };

      const savedMovie = await saveVideoToCloud(
        metadata, 
        uploadType === 'file' ? videoFile : null, 
        thumbnailFile,
        (progress) => setUploadProgress(progress)
      );

      onUpload(savedMovie);
      onClose();
    } catch (err: any) {
      setUploadError(err.message || "An unexpected error occurred.");
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 sm:p-4 bg-black/90 backdrop-blur-md overflow-y-auto">
      <div className="bg-[#181818] w-full max-w-xl min-h-screen sm:min-h-0 sm:rounded-3xl overflow-hidden shadow-2xl border border-white/10 animate-in slide-in-from-bottom-4 duration-300">

        {/* Header */}
        <div className="p-4 sm:p-6 border-b border-white/10 flex items-center justify-between">
          <div className="flex flex-col">
            <h2 className="text-lg sm:text-xl font-black flex items-center text-white uppercase italic tracking-tighter">
              {isEditMode ? <Save className="w-5 h-5 sm:w-6 h-6 mr-2 text-blue-500" /> : <Cloud className="w-5 h-5 sm:w-6 h-6 mr-2 text-red-600" />}
              {isEditMode ? 'Edit Content' : 'Upload Content'}
            </h2>
            <p className="text-[9px] sm:text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">
              {isEditMode ? `Editing ID: ${movieToEdit.id.split('-')[0]}...` : 'Global Broadcast Network'}
            </p>
          </div>
          <div className="flex items-center space-x-2">
            {!isEditMode && (
              <button 
                onClick={() => setShowSetup(!showSetup)}
                className="p-2 text-gray-500 hover:text-white transition"
                title="Database Diagnostics"
              >
                <Terminal className="w-5 h-5" />
              </button>
            )}
            <button onClick={onClose} className="text-gray-500 hover:text-red-500 transition p-2">
              <X className="w-6 h-6" />
            </button>
          </div>
        </div>

        {/* Upload Mode Selector */}
        {!isEditMode && (
          <div className="flex bg-black/40 p-1 mx-5 mt-5 sm:mx-8 sm:mt-8 rounded-xl border border-white/5">
             <button 
               onClick={() => setUploadType('file')}
               className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${uploadType === 'file' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
             >
               <FileUp className="w-4 h-4" />
               <span>File Upload</span>
             </button>
             <button 
               onClick={() => setUploadType('link')}
               className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${uploadType === 'link' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}
             >
               <Link className="w-4 h-4" />
               <span>Video Link</span>
             </button>
          </div>
        )}

        {/* Upload Form */}
        <form onSubmit={handleSubmit} className="p-5 sm:p-8 space-y-5 sm:space-y-6">
          {uploadError && (
            <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-xl flex items-start space-x-3 text-red-500 text-sm animate-in shake duration-300">
              <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
              <div className="space-y-1">
                <p className="font-black uppercase tracking-widest text-[10px]">Error</p>
                <p className="opacity-80 text-xs leading-snug">{uploadError}</p>
              </div>
            </div>
          )}

          <div className="space-y-4">
            <div>
              <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5">Video Title</label>
              <input 
                type="text" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full bg-[#252525] border border-white/5 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-600 outline-none transition placeholder:text-gray-700 font-bold text-sm"
                placeholder="Ex: My Viral Masterpiece"
                required
              />
            </div>

            {uploadType === 'link' && (
              <div className="animate-in slide-in-from-top-2 duration-300">
                <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5">Video URL (Direct MP4/Stream)</label>
                <div className="relative">
                  <Link className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                  <input 
                    type="url" 
                    value={videoUrl}
                    onChange={(e) => setVideoUrl(e.target.value)}
                    className="w-full bg-[#252525] border border-white/5 rounded-xl pl-11 pr-4 py-3 text-white focus:ring-2 focus:ring-red-600 outline-none transition placeholder:text-gray-700 font-bold text-sm"
                    placeholder="https://example.com/video.mp4"
                    required
                  />
                </div>
              </div>
            )}

            <div>
              <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5">Category</label>
              <select 
                value={genre}
                onChange={(e) => setGenre(e.target.value)}
                className="w-full bg-[#252525] border border-white/5 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-600 outline-none transition font-bold text-sm"
              >
                <option value="Viral">Viral</option>
                <option value="Insta post">Insta post</option>
                <option value="onlyfans">onlyfans</option>
                <option value="Action">Action</option>
              </select>
            </div>

            <div className="grid grid-cols-1 xs:grid-cols-2 gap-3 sm:gap-4">
               {uploadType === 'file' ? (
                 <label className="flex flex-col items-center justify-center border-2 border-dashed border-white/5 rounded-2xl p-4 cursor-pointer hover:border-red-600/50 hover:bg-white/5 transition group h-32 sm:h-40">
                    <Film className={`w-8 h-8 transition-colors ${videoFile ? 'text-green-500' : 'text-gray-600 group-hover:text-red-500'}`} />
                    <span className="text-[10px] mt-2 font-black uppercase tracking-tighter text-gray-500 text-center px-2 truncate w-full">
                      {videoFile ? videoFile.name : (isEditMode ? 'Keep existing video' : 'Choose Video File')}
                    </span>
                    <input type="file" accept="video/*" className="hidden" onChange={handleVideoChange} />
                 </label>
               ) : (
                  <div className="flex flex-col items-center justify-center border-2 border-dashed border-white/10 rounded-2xl p-4 bg-white/5 h-32 sm:h-40 opacity-60">
                    <Film className="w-8 h-8 text-red-600" />
                    <span className="text-[9px] mt-2 font-black uppercase tracking-widest text-gray-400 text-center">Remote Link Active</span>
                  </div>
               )}

               <label className="relative flex flex-col items-center justify-center border-2 border-dashed border-white/5 rounded-2xl p-4 cursor-pointer hover:border-red-600/50 hover:bg-white/5 transition group h-32 sm:h-40 overflow-hidden">
                  {thumbnailPreview ? (
                    <img src={thumbnailPreview} className="absolute inset-0 w-full h-full object-cover opacity-60" alt="" />
                  ) : thumbnailUrl ? (
                    <img src={thumbnailUrl} className="absolute inset-0 w-full h-full object-cover opacity-40" alt="" />
                  ) : (
                    <ImageIcon className="w-8 h-8 text-gray-600 group-hover:text-red-500" />
                  )}
                  <span className="relative z-10 text-[10px] mt-2 font-black uppercase tracking-tighter text-white bg-black/40 px-2 py-1 rounded">
                    {thumbnailFile ? 'New Cover' : (isEditMode ? 'Change Cover' : 'Set Thumbnail')}
                  </span>
                  <input type="file" accept="image/*" className="hidden" onChange={handleThumbnailChange} />
               </label>
            </div>

            {uploadType === 'link' && (
               <div>
                  <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1.5">Thumbnail Link (Optional)</label>
                  <input 
                    type="url" 
                    value={thumbnailUrl}
                    onChange={(e) => {
                      setThumbnailUrl(e.target.value);
                      setThumbnailFile(null);
                      setThumbnailPreview(null);
                    }}
                    className="w-full bg-[#252525] border border-white/5 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-600 outline-none transition placeholder:text-gray-700 font-bold text-sm"
                    placeholder="https://example.com/thumb.jpg"
                  />
               </div>
            )}
          </div>

          {isUploading && (
            <div className="space-y-2 animate-in fade-in duration-300">
              <div className="flex justify-between text-[9px] font-black text-red-500 uppercase tracking-[0.2em]">
                <span>Processing</span>
                <span>{uploadProgress}%</span>
              </div>
              <div className="w-full bg-white/5 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-red-600 transition-all duration-300 shadow-[0_0_10px_rgba(229,9,20,0.5)]"
                  style={{ width: `${uploadProgress}%` }}
                />
              </div>
            </div>
          )}

          <button 
            type="submit" 
            disabled={isUploading}
            className={`w-full text-white font-black py-4 sm:py-5 rounded-2xl transition disabled:opacity-50 flex items-center justify-center shadow-xl active:scale-[0.98] uppercase tracking-[0.2em] text-xs sm:text-sm ${isEditMode ? 'bg-blue-600 hover:bg-blue-700' : 'bg-red-600 hover:bg-red-700'}`}
          >
            {isUploading ? (
              <div className="flex items-center">
                <Loader2 className="w-4 h-4 animate-spin mr-3" />
                Wait...
              </div>
            ) : isEditMode ? 'Update Broadcast' : 'Push to Cloud'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default UploadModal;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import MovieRow from './components/MovieRow.tsx';
import MovieDetails from './components/MovieDetails.tsx';
import UploadModal from './components/UploadModal.tsx';
import VideoPlayer from './components/VideoPlayer.tsx';
import LoginModal from './components/LoginModal.tsx';
import AgeDisclaimer from './components/AgeDisclaimer.tsx';
import NativeAd from './components/NativeAd.tsx';
import AdBanner from './components/AdBanner.tsx';
import { INITIAL_MOVIES } from './constants.ts';
import { Movie, User } from './types.ts';
import { getAllVideosFromCloud } from './services/storageService.ts';
import { supabase } from './services/supabaseClient.ts';
import { signOut } from './services/authService.ts';
import { Database, Wifi, WifiOff, Loader2, X } from 'lucide-react';

const STORAGE_KEYS = {
  HISTORY: 'gemini_stream_history',
  AGE_VERIFIED: 'geministream_age_verified'
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [movies, setMovies] = useState<Movie[]>(INITIAL_MOVIES);
  const [selectedMovie, setSelectedMovie] = useState<Movie | null>(null);
  const [playingMovie, setPlayingMovie] = useState<Movie | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [editingMovie, setEditingMovie] = useState<Movie | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAgeVerified, setIsAgeVerified] = useState<boolean>(true); 
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(true);
  const [isOnline, setIsOnline] = useState(true);
  const [isDeepLinking, setIsDeepLinking] = useState(false);

  const pendingVideoId = useRef<string | null>(new URLSearchParams(window.location.search).get('v'));
  const selectedMovieRef = useRef<Movie | null>(null);

  useEffect(() => {
    selectedMovieRef.current = selectedMovie;
  }, [selectedMovie]);

  useEffect(() => {
    const verified = localStorage.getItem(STORAGE_KEYS.AGE_VERIFIED);
    setIsAgeVerified(verified === 'true');

    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      }
    });

    const { data: { subscription: authSub } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      } else {
        setUser(null);
      }
    });

    const syncCloudData = async () => {
      setIsSyncing(true);
      try {
        const cloudVideos = await getAllVideosFromCloud();
        const updatedMovies = [...cloudVideos, ...INITIAL_MOVIES];
        const uniqueMovies = Array.from(new Map(updatedMovies.map(m => [m.id, m])).values());
        setMovies(uniqueMovies);
        setIsOnline(true);
      } catch (err) {
        console.error("Supabase Connection Failed:", err);
        setIsOnline(false);
      } finally {
        setIsSyncing(false);
      }
    };

    syncCloudData();

    const moviesChannel = supabase
      .channel('movies-realtime-global')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'movies' }, (payload) => {
        if (payload.eventType === 'UPDATE') {
          const updatedMovie: Movie = {
            id: payload.new.id,
            title: payload.new.title,
            description: payload.new.description,
            thumbnail: payload.new.thumbnail,
            videoUrl: payload.new.video_url,
            genre: payload.new.genre,
            year: payload.new.year,
            rating: payload.new.rating,
            views: Number(payload.new.views) || 0,
            isUserUploaded: payload.new.is_user_uploaded,
            uploaderId: payload.new.uploader_id,
            uploaderName: payload.new.uploader_name
          };
          setMovies(prev => prev.map(m => m.id === updatedMovie.id ? updatedMovie : m));
          if (selectedMovieRef.current?.id === updatedMovie.id) {
            setSelectedMovie(updatedMovie);
          }
        } else if (payload.eventType === 'INSERT') {
          const newMovie: Movie = {
            id: payload.new.id,
            title: payload.new.title,
            description: payload.new.description,
            thumbnail: payload.new.thumbnail,
            videoUrl: payload.new.video_url,
            genre: payload.new.genre,
            year: payload.new.year,
            rating: payload.new.rating,
            views: payload.new.views || 0,
            isUserUploaded: payload.new.is_user_uploaded,
            uploaderId: payload.new.uploader_id,
            uploaderName: payload.new.uploader_name
          };
          setMovies(prev => [newMovie, ...prev]);
        } else if (payload.eventType === 'DELETE') {
          setMovies(prev => prev.filter(m => m.id !== payload.old.id));
          if (selectedMovieRef.current?.id === payload.old.id) {
            setSelectedMovie(null);
          }
        }
      })
      .subscribe();

    return () => {
      authSub.unsubscribe();
      supabase.removeChannel(moviesChannel);
    };
  }, []);

  useEffect(() => {
    const processDeepLink = () => {
      const params = new URLSearchParams(window.location.search);
      const videoId = params.get('v');
      const autoplay = params.get('autoplay') === 'true';

      if (videoId) {
        const target = movies.find(m => m.id === videoId);
        if (target) {
          setIsDeepLinking(false);
          pendingVideoId.current = null;
          if (autoplay) {
            setPlayingMovie(target);
            setSelectedMovie(null);
          } else {
            setSelectedMovie(target);
            setPlayingMovie(null);
          }
        } else {
          setIsDeepLinking(true);
        }
      } else {
        setIsDeepLinking(false);
      }
    };

    processDeepLink();
    window.addEventListener('popstate', processDeepLink);
    return () => window.removeEventListener('popstate', processDeepLink);
  }, [movies]);

  const handleLogout = async () => {
    try {
      await signOut();
      setUser(null);
    } catch (err) {
      console.error("Logout error", err);
    }
  };

  const handlePlay = (movie: Movie) => {
    setSelectedMovie(null);
    setPlayingMovie(movie);
  };

  const handleEdit = (movie: Movie) => {
    setEditingMovie(movie);
    setShowUploadModal(true);
  };

  const filteredMovies = useMemo(() => {
    const term = searchTerm.toLowerCase();
    if (!term) return movies;
    return movies.filter(m => 
      m.title.toLowerCase().includes(term) || 
      m.genre.toLowerCase().includes(term) ||
      (m.uploaderName && m.uploaderName.toLowerCase().includes(term))
    );
  }, [movies, searchTerm]);

  const rows = useMemo(() => {
    const userUploadsOnly = filteredMovies.filter(m => m.isUserUploaded === true);

    return [
      { 
        title: 'Trending Now', 
        movies: [...userUploadsOnly].sort((a,b) => b.views - a.views) 
      },
      { title: 'New Community Uploads', movies: userUploadsOnly.slice(0, 10) },
      { title: 'onlyfans Content', movies: filteredMovies.filter(m => m.genre === 'onlyfans') },
      { title: 'Insta post', movies: filteredMovies.filter(m => m.genre === 'Insta post') },
      { title: 'Viral Highlights', movies: filteredMovies.filter(m => m.genre === 'Viral') },
      { title: 'Premium Movies', movies: filteredMovies.filter(m => !m.isUserUploaded) },
    ];
  }, [filteredMovies]);

  return (
    <div className={`relative min-h-screen pb-20 bg-[#141414] ${!isAgeVerified ? 'max-h-screen overflow-hidden' : ''}`}>
      {!isAgeVerified && <AgeDisclaimer onVerify={() => {
        localStorage.setItem(STORAGE_KEYS.AGE_VERIFIED, 'true');
        setIsAgeVerified(true);
      }} />}

      <Navbar 
        user={user}
        onUploadClick={() => {
          setEditingMovie(null);
          user ? setShowUploadModal(true) : setShowLoginModal(true);
        }} 
        onLoginClick={() => setShowLoginModal(true)}
        onLogout={handleLogout}
        onSearch={setSearchTerm}
      />

      {isDeepLinking && isSyncing && (
        <div className="fixed inset-0 z-[80] bg-black/90 flex flex-col items-center justify-center space-y-4">
           <Loader2 className="w-12 h-12 text-red-600 animate-spin" />
           <p className="text-white font-bold uppercase tracking-widest text-sm animate-pulse">Fetching shared content...</p>
        </div>
      )}

      {!searchTerm && movies.length > 0 && (
        <Hero 
          movie={movies[0]} 
          onInfoClick={setSelectedMovie} 
          onPlay={handlePlay}
        />
      )}

      <div className={`${searchTerm ? 'pt-24' : '-mt-32 relative z-20'} transition-all duration-500`}>
        <div className="px-4 md:px-12 mb-6 flex items-center justify-between">
          <div className="flex items-center space-x-3">
             <div className={`p-1.5 rounded-lg ${isOnline ? 'bg-green-600/10 text-green-500' : 'bg-red-600/10 text-red-500'}`}>
                {isOnline ? <Wifi className="w-4 h-4" /> : <WifiOff className="w-4 h-4" />}
             </div>
             <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-tighter text-gray-500">Supabase Connection</span>
                <span className="text-xs font-bold text-white leading-none">Status: {isOnline ? 'Online' : 'Offline'}</span>
             </div>
          </div>

          {isSyncing && (
            <div className="flex items-center space-x-2 text-[10px] font-bold text-orange-500 uppercase tracking-widest animate-pulse">
               <Database className="w-3 h-3" />
               <span>Syncing Realtime...</span>
            </div>
          )}
        </div>

        {/* PRIMARY AD PLACEMENT - TOP OF FEED FOR MAX REVENUE */}
        <AdBanner />

        {rows.map((row, idx) => (
          <React.Fragment key={row.title + idx}>
            <MovieRow 
              title={row.title}
              movies={row.movies}
              onMovieClick={setSelectedMovie}
              onPlay={handlePlay}
            />
            {idx === 0 && <NativeAd />}
          </React.Fragment>
        ))}
      </div>

      {selectedMovie && (
        <MovieDetails 
          movie={selectedMovie} 
          allMovies={movies}
          user={user}
          onClose={() => setSelectedMovie(null)} 
          onPlay={handlePlay} 
          onMovieSelect={setSelectedMovie}
          onEdit={handleEdit}
        />
      )}

      {playingMovie && (
        <VideoPlayer movie={playingMovie} onClose={() => setPlayingMovie(null)} />
      )}

      {showUploadModal && user && (
        <UploadModal 
          user={user}
          movieToEdit={editingMovie}
          onClose={() => {
            setShowUploadModal(false);
            setEditingMovie(null);
          }} 
          onUpload={(m) => {
            if (editingMovie) {
               setMovies(prev => prev.map(old => old.id === m.id ? m : old));
            } else {
               setMovies(prev => [m, ...prev]);
            }
          }} 
        />
      )}

      {showLoginModal && (
        <LoginModal 
          onLogin={() => setShowLoginModal(false)} 
          onClose={() => setShowLoginModal(false)} 
        />
      )}

      <footer className="px-4 md:px-12 py-16 border-t border-white/5 text-gray-600 text-sm mt-20 text-center pb-10">
        <div className="flex flex-col items-center space-y-4">
          <div className="flex items-center space-x-2 bg-white/5 px-4 py-2 rounded-full border border-white/10">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-ping" />
            <span className="text-[10px] font-black uppercase tracking-widest text-white">Live Backend Linked</span>
          </div>
          <p>© 2024 GeminiStream Platform.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { X, Play, Share2, Check, Eye, TrendingUp, PlayCircle, Trash2, Edit3, AlertCircle, Loader2 } from 'lucide-react';
import { Movie, User } from '../types.ts';
import { deleteVideoFromCloud } from '../services/storageService.ts';
import AdBanner from './AdBanner.tsx';

interface MovieDetailsProps {
  movie: Movie;
  allMovies: Movie[];
  user: User | null;
  onClose: () => void;
  onPlay: (movie: Movie) => void;
  onMovieSelect: (movie: Movie) => void;
  onEdit: (movie: Movie) => void;
}

const formatViews = (views: number) => {
  if (views >= 1000000) return (views / 1000000).toFixed(1) + 'M';
  if (views >= 1000) return (views / 1000).toFixed(1) + 'K';
  return views.toString();
};

const MovieDetails: React.FC<MovieDetailsProps> = ({ movie, allMovies, user, onClose, onPlay, onMovieSelect, onEdit }) => {
  const [copied, setCopied] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);

  const isOwner = user && movie.uploaderId === user.id;

  useEffect(() => {
    const modal = document.querySelector('.modal-scroll-container');
    if (modal) modal.scrollTo({ top: 0, behavior: 'smooth' });
  }, [movie.id]);

  const suggestions = useMemo(() => {
    return allMovies
      .filter(m => m.id !== movie.id)
      .sort((a, b) => b.views - a.views)
