 *   is_user_uploaded boolean default true,
 *   uploader_id uuid references auth.users(id) on delete cascade,
 *   uploader_name text
 * );
 * 
 * -- 2. Enable Row Level Security
 * alter table public.movies enable row level security;
 * 
 * -- 3. Create Table Policies
 * create policy "Allow public read access" on public.movies for select using (true);
 * create policy "Allow individual insert" on public.movies for insert with check (auth.uid() = uploader_id);
 * create policy "Allow individual update" on public.movies for update using (auth.uid() = uploader_id);
 * create policy "Allow individual delete" on public.movies for delete using (auth.uid() = uploader_id);
 * 
 * -- 4. Create the view increment function
 * create or replace function public.increment_views(movie_id uuid)
 * returns void as $$
 * begin
 *   update public.movies set views = views + 1 where id = movie_id;
 * end;
 * $$ language plpgsql security definer;
 * 
 * -- 5. Storage Bucket Setup (Public Buckets)
 * insert into storage.buckets (id, name, public) values ('videos', 'videos', true), ('thumbnails', 'thumbnails', true)
 * on conflict (id) do update set public = true;
 * 
 * -- 6. Storage Policies
 * create policy "Public Access" on storage.objects for select using (bucket_id in ('videos', 'thumbnails'));
 * create policy "Authenticated Manage" on storage.objects for all using (bucket_id in ('videos', 'thumbnails') AND auth.role() = 'authenticated');
 */

export const saveVideoToCloud = async (
  movieMetadata: Partial<Movie>, 
  videoFile?: File | null, 
  thumbnailFile?: File | null,
  onProgress?: (progress: number) => void
): Promise<Movie> => {

  const uploadFile = async (bucket: string, file: File) => {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Math.random().toString(36).substring(2)}-${Date.now()}.${fileExt}`;
    const filePath = `${fileName}`;

    const { data, error } = await supabase.storage
      .from(bucket)
      .upload(filePath, file, {
        cacheControl: '3600',
        upsert: false
      });

    if (error) {
      console.error(`Storage Error [${bucket}]:`, error);
      if (error.message.includes('row-level security') || error.message.includes('403') || error.message.includes('Policy')) {
        throw new Error(`STORAGE_RLS_ERROR: ${bucket}. Ensure bucket is Public and Policies are set.`);
      }
      throw new Error(`Storage Error (${bucket}): ${error.message}`);
    }

    const { data: { publicUrl } } = supabase.storage
      .from(bucket)
      .getPublicUrl(filePath);

    return publicUrl;
  };

  try {
    let finalThumbnailUrl = movieMetadata.thumbnail;
    let finalVideoUrl = movieMetadata.videoUrl;

    if (thumbnailFile) {
      finalThumbnailUrl = await uploadFile('thumbnails', thumbnailFile);
    }

    if (videoFile) {
      if (onProgress) onProgress(10);
      finalVideoUrl = await uploadFile('videos', videoFile);
      if (onProgress) onProgress(80);
    }

    if (!finalVideoUrl) throw new Error("Missing video source.");

    // Update existing movie
    if (movieMetadata.id) {
       const { data, error: updateError } = await supabase
        .from('movies')
        .update({
          title: movieMetadata.title,
          description: movieMetadata.description,
          genre: movieMetadata.genre,
          thumbnail: finalThumbnailUrl,
          video_url: finalVideoUrl
        })
        .eq('id', movieMetadata.id)
        .eq('uploader_id', movieMetadata.uploaderId)
        .select();

      if (updateError) {
        if (updateError.code === '42501') throw new Error("DATABASE_RLS_ERROR: UPDATE permission denied.");
        throw updateError;
      }
      if (!data || data.length === 0) throw new Error("DATABASE_RLS_ERROR: Update failed (check ownership).");

      return mapDbToMovie(data[0]);
    }

    // Insert new movie
    const payload = {
      title: movieMetadata.title || 'Untitled',
      description: movieMetadata.description || '',
      thumbnail: finalThumbnailUrl,
      video_url: finalVideoUrl,
      genre: movieMetadata.genre || 'Viral',
      year: movieMetadata.year || new Date().getFullYear(),
      rating: movieMetadata.rating || 'NR',
      views: 0,
      is_user_uploaded: true,
      uploader_id: movieMetadata.uploaderId,
      uploader_name: movieMetadata.uploaderName || 'Anonymous'
    };

    const { data, error: dbError } = await supabase
      .from('movies')
      .insert([payload])
      .select();

    if (dbError) {
       if (dbError.code === '42501') throw new Error("DATABASE_RLS_ERROR: INSERT permission denied.");
       throw dbError;
    }
    if (!data || data.length === 0) throw new Error("DATABASE_RLS_ERROR: Insert failed.");

    return mapDbToMovie(data[0]);
  } catch (error: any) {
    console.error("Upload Operation Error:", error);
    throw error;
  }
};

export const deleteVideoFromCloud = async (movieId: string): Promise<void> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) throw new Error("Not signed in.");

  const { error } = await supabase
    .from('movies')
    .delete()
    .eq('id', movieId)
    .eq('uploader_id', user.id);

  if (error) throw new Error(`DATABASE_RLS_ERROR: DELETE`);
};

export const incrementMovieView = async (movieId: string) => {
  const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(movieId);
  if (!isUuid) return;
  try {
    await supabase.rpc('increment_views', { movie_id: movieId });
  } catch (err) {}
};

export const getAllVideosFromCloud = async (): Promise<Movie[]> => {
  const { data, error } = await supabase
    .from('movies')
    .select('*')
    .order('created_at', { ascending: false });
  return (data || []).map(mapDbToMovie);
};

const mapDbToMovie = (item: any): Movie => ({
  id: item.id,
  title: item.title,
  description: item.description,
  thumbnail: item.thumbnail,
  videoUrl: item.video_url,
  genre: item.genre,
  year: item.year,
  rating: item.rating,
  views: Number(item.views) || 0,
  isUserUploaded: item.is_user_uploaded,
  uploaderId: item.uploader_id,
  uploaderName: item.uploader_name
});

import React, { useRef, useState } from 'react';
import { ChevronLeft, ChevronRight, Share2, Check, Eye, Link } from 'lucide-react';
import { Movie } from '../types.ts';

interface MovieRowProps {
  title: string;
  movies: Movie[];
  onMovieClick: (movie: Movie) => void;
  onPlay: (movie: Movie) => void;
}

const formatViews = (views: number) => {
  if (views >= 1000000) return (views / 1000000).toFixed(1) + 'M';
  if (views >= 1000) return (views / 1000).toFixed(1) + 'K';
  return views.toString();
};

const MovieRow: React.FC<MovieRowProps> = ({ title, movies, onMovieClick, onPlay }) => {
  const rowRef = useRef<HTMLDivElement>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [copiedCategory, setCopiedCategory] = useState(false);

  const scroll = (direction: 'left' | 'right') => {
    if (rowRef.current) {
      const { scrollLeft, clientWidth } = rowRef.current;
      const scrollTo = direction === 'left' ? scrollLeft - clientWidth : scrollLeft + clientWidth;
      rowRef.current.scrollTo({ left: scrollTo, behavior: 'smooth' });
    }
  };

  const handleShareMovie = async (e: React.MouseEvent, movie: Movie) => {
    e.stopPropagation();
    const shareUrl = `${window.location.origin}?v=${movie.id}`;
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopiedId(movie.id);
      setTimeout(() => setCopiedId(null), 2000);
    } catch (err) {
      console.error('Failed to copy link:', err);
    }
  };

  const handleShareCategory = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareUrl = `${window.location.origin}?cat=${encodeURIComponent(title)}`;
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopiedCategory(true);
      setTimeout(() => setCopiedCategory(false), 2000);
    } catch (err) {
      console.error('Failed to copy category link:', err);
    }
  };

  if (movies.length === 0) return null;

  return (
    <div id={`row-${title.replace(/\s+/g, '-').toLowerCase()}`} className="space-y-4 mb-10 group/row">
      <div className="flex items-center px-4 md:px-12 justify-between">
        <div className="flex items-center space-x-3">
          <h3 className="text-xl md:text-3xl font-black text-white uppercase tracking-tighter italic">
            {title}
          </h3>
          <button 
            onClick={handleShareCategory}
            className={`flex items-center space-x-2 px-3 py-1.5 rounded-full border transition-all duration-500 ${copiedCategory ? 'bg-green-600 border-green-500 scale-105 shadow-[0_0_15px_rgba(34,197,94,0.4)]' : 'bg-white/5 border-white/10 hover:bg-red-600 hover:border-red-500 hover:shadow-[0_0_15px_rgba(229,9,20,0.3)]'}`}
            title="Share Entire Category"
          >
            {copiedCategory ? (
              <Check className="w-3.5 h-3.5 text-white" />
            ) : (
              <Share2 className="w-3.5 h-3.5 text-gray-400 group-hover/row:text-white" />
            )}
            <span className={`text-[10px] font-black uppercase tracking-widest hidden sm:inline ${copiedCategory ? 'text-white' : 'text-gray-400 group-hover/row:text-white'}`}>
              {copiedCategory ? 'Link Copied' : 'Share Category'}
            </span>
          </button>

          {copiedCategory && (
            <span className="text-[10px] font-black text-green-500 uppercase tracking-widest animate-in fade-in slide-in-from-left-2 md:hidden">
              Copied!
            </span>
          )}
        </div>

        <div className="hidden md:flex items-center space-x-1 opacity-0 group-hover/row:opacity-100 transition-opacity duration-500">
           <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Explore all</span>
           <ChevronRight className="w-4 h-4 text-gray-500" />
        </div>
      </div>

      <div className="group relative flex items-center">
        <button 
          onClick={() => scroll('left')}
          className="absolute left-0 z-30 p-2 bg-black/70 h-full opacity-0 group-hover:opacity-100 transition duration-300 hover:scale-110 md:px-4"
        >
          <ChevronLeft className="w-8 h-8" />
        </button>

        <div 
          ref={rowRef}
          className="row-container flex space-x-2 md:space-x-5 overflow-x-auto px-4 md:px-12 scroll-smooth py-4"
        >
          {movies.map((movie) => (
            <div 
              key={movie.id}
              onClick={() => onMovieClick(movie)}
              className="relative flex-none w-48 h-28 md:w-80 md:h-44 cursor-pointer transition-all duration-500 hover:scale-105 hover:z-20 rounded-2xl overflow-hidden bg-zinc-900 group/card shadow-2xl hover:shadow-red-600/30 border border-white/5"
            >
              <img 
                src={movie.thumbnail} 
                alt={movie.title} 
                className="w-full h-full object-cover brightness-[0.9] group-hover/card:brightness-75 transition-all duration-500"
              />

              <div className="absolute top-2 right-2 z-30 flex flex-col space-y-2 opacity-100 md:opacity-0 md:group-hover/card:opacity-100 transition-all duration-300 translate-y-2 group-hover/card:translate-y-0">
                <button 
                  onClick={(e) => handleShareMovie(e, movie)}
                  className="p-2 bg-black/60 backdrop-blur-md rounded-full border border-white/10 hover:bg-red-600 transition-colors shadow-lg"
                >
                  {copiedId === movie.id ? <Check className="w-4 h-4 text-white" /> : <Share2 className="w-4 h-4 text-white" />}
                </button>
              </div>

              <div className="absolute top-3 left-3 z-30 flex items-center bg-black/60 backdrop-blur-md px-2 py-1 rounded-lg text-[10px] font-black text-white border border-white/5">
                <Eye className="w-3.5 h-3.5 mr-1 text-red-500 fill-red-500" />
                <span>{formatViews(movie.views)}</span>
              </div>

              <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black via-black/90 to-transparent p-4 md:p-6 opacity-100 md:opacity-0 md:group-hover/card:opacity-100 transition-all duration-300 transform translate-y-4 group-hover/card:translate-y-0">
                 <p className="text-xs md:text-lg font-black text-white truncate pr-8 uppercase italic leading-tight tracking-tight">{movie.title}</p>
                 <div className="flex items-center space-x-2 text-[8px] md:text-[11px] text-green-400 font-black mt-1 uppercase tracking-widest">
                    <span className="border border-green-500/30 px-1 rounded-sm">{movie.rating}</span>
                    <span className="text-gray-500">•</span>
                    <span>{movie.year}</span>
                    {movie.isUserUploaded && <span className="bg-red-600 text-white px-2 py-0.5 rounded-sm text-[8px] md:text-[10px] ml-auto">UGC</span>}
                 </div>
              </div>
            </div>
          ))}
        </div>

        <button 
          onClick={() => scroll('right')}
          className="absolute right-0 z-30 p-2 bg-black/70 h-full opacity-0 group-hover:opacity-100 transition duration-300 hover:scale-110 md:px-4"
        >
          <ChevronRight className="w-8 h-8" />
        </button>
      </div>
    </div>
  );
};

