        </button>
      </div>
    </div>
  );
};

export default MovieRow;

import React, { useState, useEffect, useMemo } from 'react';
import { X, Play, Share2, Check, Eye, TrendingUp, PlayCircle, Trash2, Edit3, AlertCircle, Loader2 } from 'lucide-react';
import { Movie, User } from '../types.ts';
import { deleteVideoFromCloud } from '../services/storageService.ts';
import AdBanner from './AdBanner.tsx';

interface MovieDetailsProps {
  movie: Movie;
  allMovies: Movie[];
  user: User | null;
  onClose: () => void;
  onPlay: (movie: Movie) => void;
  onMovieSelect: (movie: Movie) => void;
  onEdit: (movie: Movie) => void;
}

const formatViews = (views: number) => {
  if (views >= 1000000) return (views / 1000000).toFixed(1) + 'M';
  if (views >= 1000) return (views / 1000).toFixed(1) + 'K';
  return views.toString();
};

const MovieDetails: React.FC<MovieDetailsProps> = ({ movie, allMovies, user, onClose, onPlay, onMovieSelect, onEdit }) => {
  const [copied, setCopied] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);

  const isOwner = user && movie.uploaderId === user.id;

  useEffect(() => {
    const modal = document.querySelector('.modal-scroll-container');
    if (modal) modal.scrollTo({ top: 0, behavior: 'smooth' });
  }, [movie.id]);

  const suggestions = useMemo(() => {
    return allMovies
      .filter(m => m.id !== movie.id)
      .sort((a, b) => b.views - a.views)
      .slice(0, 8);
  }, [allMovies, movie.id]);

  const handleShare = async () => {
    const shareUrl = `${window.location.origin}?v=${movie.id}&autoplay=true`;
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy link:', err);
    }
  };

  const handleDelete = async () => {
    if (!movie.id) return;
    setIsDeleting(true);
    try {
      await deleteVideoFromCloud(movie.id);
      onClose();
    } catch (err) {
      console.error(err);
      setIsDeleting(false);
      setShowConfirmDelete(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-6 bg-black/90 backdrop-blur-md overflow-y-auto modal-scroll-container">
      <div className="relative bg-[#141414] w-full max-w-3xl min-h-screen md:min-h-0 md:rounded-2xl overflow-hidden shadow-2xl border border-white/5 animate-in fade-in zoom-in-95 duration-200">

        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 z-[70] bg-black/60 hover:bg-red-600 p-2 rounded-full transition-all active:scale-90 shadow-lg"
        >
          <X className="w-6 h-6 text-white" />
        </button>

        {/* 1. Video Thumbnail with Central Play Button */}
        <div className="relative aspect-video group">
          <img 
            src={movie.thumbnail} 
            alt={movie.title} 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-[#141414] via-transparent to-black/20" />

          <div className="absolute inset-0 flex items-center justify-center">
             <button 
              onClick={() => onPlay(movie)}
              className="bg-red-600 text-white w-16 h-16 md:w-24 md:h-24 rounded-full flex items-center justify-center shadow-[0_0_40px_rgba(229,9,20,0.5)] hover:scale-110 active:scale-95 transition-all duration-300 border-4 border-white/20"
             >
                <Play className="w-8 h-8 md:w-12 md:h-12 fill-white ml-1 md:ml-2" />
             </button>
          </div>

          {/* Owner Badge */}
          {isOwner && (
            <div className="absolute top-4 left-4 flex items-center bg-blue-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest text-white shadow-xl border border-blue-400/30">
              Your Upload
            </div>
          )}
        </div>

        {/* 2. Content Details & Actions */}
        <div className="p-5 md:p-8 space-y-5 md:space-y-6">
          {/* Owner controls */}
          {isOwner && (
            <div className="flex items-center space-x-3 bg-white/5 p-4 rounded-xl border border-white/5">
              <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest mr-auto">Owner Controls</span>
              <button 
                onClick={() => onEdit(movie)}
                className="flex items-center space-x-1.5 px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg text-xs font-bold transition"
              >
                <Edit3 className="w-3.5 h-3.5" />
                <span>Edit</span>
              </button>

              {!showConfirmDelete ? (
                <button 
                  onClick={() => setShowConfirmDelete(true)}
                  className="flex items-center space-x-1.5 px-3 py-1.5 bg-red-600/10 hover:bg-red-600/20 text-red-500 rounded-lg text-xs font-bold transition"
                >
                  <Trash2 className="w-3.5 h-3.5" />
                  <span>Delete</span>
                </button>
              ) : (
                <div className="flex items-center space-x-2 animate-in slide-in-from-right-2 duration-200">
                  <span className="text-[10px] text-red-500 font-bold uppercase">Confirm?</span>
                  <button 
                    disabled={isDeleting}
                    onClick={handleDelete}
                    className="p-1.5 bg-red-600 text-white rounded-lg hover:bg-red-700 transition"
                  >
                    {isDeleting ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Check className="w-3.5 h-3.5" />}
                  </button>
                  <button 
                    onClick={() => setShowConfirmDelete(false)}
                    className="p-1.5 bg-zinc-800 text-white rounded-lg hover:bg-zinc-700 transition"
                  >
                    <X className="w-3.5 h-3.5" />
                  </button>
                </div>
              )}
            </div>
          )}

          <div className="space-y-2">
            <h2 className="text-2xl md:text-4xl font-black text-white uppercase tracking-tighter italic leading-none">
              {movie.title}
            </h2>
            <div className="flex items-center space-x-3 md:space-x-4 text-[10px] md:text-xs font-bold text-gray-500 uppercase tracking-widest">
              <span>{movie.year}</span>
              <span>•</span>
              <span className="text-green-500">{movie.rating}</span>
              <span>•</span>
              <span className="flex items-center">
                <Eye className="w-3 h-3 mr-1" /> {formatViews(movie.views)}
              </span>
            </div>
          </div>

          <p className="text-gray-400 text-sm md:text-base leading-relaxed line-clamp-4">
            {movie.description}
          </p>

          <div className="flex flex-col sm:flex-row gap-3 pt-2">
            <button 
              onClick={() => onPlay(movie)}
              className="flex-1 bg-white text-black py-3 md:py-4 rounded-xl flex items-center justify-center font-black uppercase tracking-widest hover:bg-gray-200 transition-all active:scale-95 shadow-lg text-xs md:text-sm"
            >
              <PlayCircle className="w-5 h-5 md:w-6 md:h-6 mr-2 fill-black" />
              Watch Now
            </button>

            <button 
              onClick={handleShare}
              className={`flex-1 py-3 md:py-4 rounded-xl flex items-center justify-center font-black uppercase tracking-widest transition-all active:scale-95 border-2 text-xs md:text-sm ${copied ? 'bg-green-600 border-green-600 text-white' : 'bg-transparent border-white/10 text-white hover:bg-white/5'}`}
            >
              {copied ? <Check className="w-5 h-5 md:w-6 md:h-6 mr-2" /> : <Share2 className="w-5 h-5 md:w-6 md:h-6 mr-2" />}
              {copied ? 'Link Copied' : 'Share Link'}
            </button>
          </div>

          <div className="py-2 overflow-hidden">
            <AdBanner />
          </div>

          <div className="pt-6 md:pt-8 border-t border-white/5 space-y-4">
            <div className="flex items-center space-x-2 text-gray-100">
              <TrendingUp className="w-5 h-5 text-red-600" />
              <h3 className="text-base md:text-lg font-black uppercase tracking-tighter">Recommended</h3>
            </div>

            <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 gap-3 md:gap-4">
              {suggestions.map((sug) => (
                <div 
                  key={sug.id}
                  onClick={() => onMovieSelect(sug)}
                  className="relative aspect-video rounded-lg overflow-hidden border border-white/5 cursor-pointer hover:scale-105 transition duration-300 group/sug shadow-lg"
                >
                   <img src={sug.thumbnail} alt={sug.title} className="w-full h-full object-cover brightness-75 group-hover/sug:brightness-100 transition" />
                   <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex flex-col justify-end p-2">
                      <p className="text-[10px] font-black text-white uppercase truncate">{sug.title}</p>
                      <p className="text-[8px] font-bold text-gray-400">{sug.year} • {formatViews(sug.views)}</p>
                   </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MovieDetails;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import Navbar from './components/Navbar.tsx';
import Hero from './components/Hero.tsx';
import MovieRow from './components/MovieRow.tsx';
import MovieDetails from './components/MovieDetails.tsx';
import UploadModal from './components/UploadModal.tsx';
import VideoPlayer from './components/VideoPlayer.tsx';
import LoginModal from './components/LoginModal.tsx';
import AgeDisclaimer from './components/AgeDisclaimer.tsx';
import NativeAd from './components/NativeAd.tsx';
import AdBanner from './components/AdBanner.tsx';
import CategoryShareBar from './components/CategoryShareBar.tsx';
import { INITIAL_MOVIES } from './constants.ts';
import { Movie, User } from './types.ts';
import { getAllVideosFromCloud } from './services/storageService.ts';
import { supabase } from './services/supabaseClient.ts';
import { signOut } from './services/authService.ts';
import { Database, Wifi, WifiOff, Loader2, X } from 'lucide-react';

const STORAGE_KEYS = {
  HISTORY: 'gemini_stream_history',
  AGE_VERIFIED: 'geministream_age_verified'
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [movies, setMovies] = useState<Movie[]>(INITIAL_MOVIES);
  const [selectedMovie, setSelectedMovie] = useState<Movie | null>(null);
  const [playingMovie, setPlayingMovie] = useState<Movie | null>(null);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [editingMovie, setEditingMovie] = useState<Movie | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isAgeVerified, setIsAgeVerified] = useState<boolean>(true); 
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(true);
  const [isOnline, setIsOnline] = useState(true);

  const selectedMovieRef = useRef<Movie | null>(null);
  const deepLinkProcessed = useRef(false);

  useEffect(() => {
    selectedMovieRef.current = selectedMovie;
  }, [selectedMovie]);

  useEffect(() => {
    const verified = localStorage.getItem(STORAGE_KEYS.AGE_VERIFIED);
    setIsAgeVerified(verified === 'true');

    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      }
    });

    const { data: { subscription: authSub } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          id: session.user.id,
          name: session.user.user_metadata.full_name || 'User',
          email: session.user.email || '',
          avatar: session.user.user_metadata.avatar_url || `https://ui-avatars.com/api/?name=User&background=E50914&color=fff`
        });
      } else {
        setUser(null);
      }
    });

    const syncCloudData = async () => {
      setIsSyncing(true);
      try {
        const cloudVideos = await getAllVideosFromCloud();
        const updatedMovies = [...cloudVideos, ...INITIAL_MOVIES];
        const uniqueMovies = Array.from(new Map(updatedMovies.map(m => [m.id, m])).values());
        setMovies(uniqueMovies);
        setIsOnline(true);
      } catch (err) {
        console.error("Supabase Connection Failed:", err);
        setIsOnline(false);
      } finally {
        setIsSyncing(false);
      }
    };

    syncCloudData();

    const moviesChannel = supabase
      .channel('movies-realtime-global')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'movies' }, (payload) => {
        if (payload.eventType === 'UPDATE') {
          const updatedMovie: Movie = {
            id: payload.new.id,
            title: payload.new.title,
            description: payload.new.description,
            thumbnail: payload.new.thumbnail,
            videoUrl: payload.new.video_url,
            genre: payload.new.genre,
            year: payload.new.year,
            rating: payload.new.rating,
            views: Number(payload.new.views) || 0,
            isUserUploaded: payload.new.is_user_uploaded,
            uploaderId: payload.new.uploader_id,
            uploaderName: payload.new.uploader_name
          };
          setMovies(prev => prev.map(m => m.id === updatedMovie.id ? updatedMovie : m));
          if (selectedMovieRef.current?.id === updatedMovie.id) {
            setSelectedMovie(updatedMovie);
          }
        } else if (payload.eventType === 'INSERT') {
          const newMovie: Movie = {
            id: payload.new.id,
            title: payload.new.title,
            description: payload.new.description,
            thumbnail: payload.new.thumbnail,
            videoUrl: payload.new.video_url,
            genre: payload.new.genre,
            year: payload.new.year,
            rating: payload.new.rating,
            views: payload.new.views || 0,
            isUserUploaded: payload.new.is_user_uploaded,
            uploaderId: payload.new.uploader_id,
            uploaderName: payload.new.uploader_name
          };
          setMovies(prev => [newMovie, ...prev]);
        } else if (payload.eventType === 'DELETE') {
          setMovies(prev => prev.filter(m => m.id !== payload.old.id));
          if (selectedMovieRef.current?.id === payload.old.id) {
            setSelectedMovie(null);
          }
        }
      })
      .subscribe();

    return () => {
      authSub.unsubscribe();
      supabase.removeChannel(moviesChannel);
    };
  }, []);

  const handleCategoryScroll = (categoryName: string) => {
    const targetId = `row-${categoryName.replace(/\s+/g, '-').toLowerCase()}`;
    const element = document.getElementById(targetId);
    if (element) {
      const headerOffset = 150;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });

      element.classList.add('ring-1', 'ring-red-600/50', 'bg-red-600/5', 'rounded-xl', 'transition-all');
      setTimeout(() => {
        element.classList.remove('ring-1', 'ring-red-600/50', 'bg-red-600/5');
      }, 3000);
    }
  };

  useEffect(() => {
    // Check deep link as soon as movies are available
    if (movies.length > 0 && !deepLinkProcessed.current) {
      const params = new URLSearchParams(window.location.search);
      const videoId = params.get('v');
      const category = params.get('cat');

      if (videoId) {
        const target = movies.find(m => m.id === videoId);
        if (target) {
          // Default to playing the movie if v is in URL, unless explicitly set to false
          const autoplay = params.get('autoplay') !== 'false';

          if (autoplay) {
            setPlayingMovie(target);
            setSelectedMovie(null);
          } else {
            setSelectedMovie(target);
            setPlayingMovie(null);
          }
          deepLinkProcessed.current = true;
        }
        // If target not found yet, we wait for next movies update (sync)
      } 
      else if (category) {
        const decodedCat = decodeURIComponent(category);
        setTimeout(() => handleCategoryScroll(decodedCat), 1000);
        deepLinkProcessed.current = true;
      } else {
        // No deep link params found
        deepLinkProcessed.current = true;
      }
    }
  }, [movies]);

  const handleLogout = async () => {
    try {
      await signOut();
      setUser(null);
    } catch (err) {
      console.error("Logout error", err);
    }
  };

  const handlePlay = (movie: Movie) => {
    setSelectedMovie(null);
    setPlayingMovie(movie);
  };

  const handleEdit = (movie: Movie) => {
    setEditingMovie(movie);
    setShowUploadModal(true);
  };

  const filteredMovies = useMemo(() => {
    const term = searchTerm.toLowerCase();
    if (!term) return movies;
    return movies.filter(m => 
      m.title.toLowerCase().includes(term) || 
      m.genre.toLowerCase().includes(term) ||
      (m.uploaderName && m.uploaderName.toLowerCase().includes(term))
    );
  }, [movies, searchTerm]);

  const rows = useMemo(() => {
    const userUploadsOnly = filteredMovies.filter(m => m.isUserUploaded === true);

    return [
      { 
        title: 'Trending Now', 
        movies: [...userUploadsOnly].sort((a,b) => b.views - a.views) 
      },
      { title: 'New Community Uploads', movies: userUploadsOnly.slice(0, 10) },
      { title: 'onlyfans Content', movies: filteredMovies.filter(m => m.genre === 'onlyfans') },
      { title: 'Insta post', movies: filteredMovies.filter(m => m.genre === 'Insta post') },
      { title: 'Viral Highlights', movies: filteredMovies.filter(m => m.genre === 'Viral') },
      { title: 'Premium Movies', movies: filteredMovies.filter(m => !m.isUserUploaded) }
    ];
  }, [filteredMovies]);

  return (
    <div className="min-h-screen pb-20 overflow-x-hidden">
      {!isAgeVerified && <AgeDisclaimer onVerify={() => {
        setIsAgeVerified(true);
        localStorage.setItem(STORAGE_KEYS.AGE_VERIFIED, 'true');
      }} />}

      <Navbar 
        user={user} 
        onUploadClick={() => {
          if (!user) setShowLoginModal(true);
          else {
            setEditingMovie(null);
            setShowUploadModal(true);
          }
        }} 
        onLoginClick={() => setShowLoginModal(true)} 
        onLogout={handleLogout}
        onSearch={setSearchTerm}
      />

      <Hero 
        movie={movies[0]} 
        onInfoClick={setSelectedMovie} 
        onPlay={handlePlay} 
      />

      <CategoryShareBar onCategoryClick={handleCategoryScroll} />

      <div className="relative z-20 space-y-4">
        {isSyncing && (
          <div className="flex items-center justify-center space-x-2 text-red-600 bg-black/40 backdrop-blur-md py-2 px-4 rounded-full w-fit mx-auto border border-red-600/20 shadow-lg mt-8">
             <Loader2 className="w-4 h-4 animate-spin" />
             <span className="text-[10px] font-black uppercase tracking-[0.2em]">Syncing Broadcasts</span>
          </div>
        )}

        {!isOnline && (
          <div className="flex items-center justify-center space-x-2 text-amber-500 bg-black/40 backdrop-blur-md py-2 px-4 rounded-full w-fit mx-auto border border-amber-500/20 shadow-lg animate-bounce mt-8">
             <WifiOff className="w-4 h-4" />
             <span className="text-[10px] font-black uppercase tracking-[0.2em]">Offline Mode</span>
          </div>
        )}

        <div className="space-y-4">
          {rows.map((row, idx) => (
            <React.Fragment key={row.title}>
              <MovieRow 
                title={row.title} 
                movies={row.movies} 
                onMovieClick={setSelectedMovie} 
                onPlay={handlePlay} 
              />
              {idx === 0 && <AdBanner />}
              {idx === 2 && <NativeAd />}
            </React.Fragment>
          ))}
        </div>
      </div>

      {selectedMovie && (
        <MovieDetails 
          movie={selectedMovie} 
          allMovies={movies} 
          user={user}
          onClose={() => setSelectedMovie(null)} 
          onPlay={handlePlay}
          onMovieSelect={setSelectedMovie}
          onEdit={handleEdit}
        />
      )}

      {playingMovie && (
        <VideoPlayer 
          movie={playingMovie} 
          onClose={() => setPlayingMovie(null)} 
        />
      )}

      {showUploadModal && user && (
        <UploadModal 
          user={user} 
          onClose={() => setShowUploadModal(false)} 
          onUpload={(newMovie) => {
            if (editingMovie) {
              setMovies(prev => prev.map(m => m.id === newMovie.id ? newMovie : m));
            } else {
              setMovies(prev => [newMovie, ...prev]);
            }
          }}
          movieToEdit={editingMovie}
        />
      )}

      {showLoginModal && (
        <LoginModal 
          onLogin={(u) => {
            setUser(u);
            setShowLoginModal(false);
          }}
          onClose={() => setShowLoginModal(false)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Search, Bell, User as UserIcon, Plus, Film, LogOut, Crown } from 'lucide-react';
import { User } from '../types.ts';

