                    <button onClick={toggleMute} className="text-white hover:scale-110 transition p-1">
                      {isMuted || volume === 0 ? <VolumeX className="w-5 h-5 md:w-8 md:h-8" /> : <Volume2 className="w-5 h-5 md:w-8 md:h-8" />}
