  const [copiedField, setCopiedField] = useState<string | null>(null);

  // Generates a thumbnail from a video file at 1.5s mark
  const generateThumbnail = useCallback(async (file: File) => {
    if (!file) return;
    setIsGeneratingThumbnail(true);
    setWasAutoGenerated(false);

    const video = document.createElement('video');
    const url = URL.createObjectURL(file);

    video.src = url;
    video.muted = true;
    video.playsInline = true;
    video.preload = 'auto';
    video.crossOrigin = "anonymous"; 

    const capture = () => {
      return new Promise<void>((resolve, reject) => {
        video.onloadedmetadata = () => {
          video.currentTime = Math.min(1.5, video.duration / 2);
        };

        video.onseeked = () => {
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            canvas.toBlob((blob) => {
              if (blob) {
                const generatedFile = new File([blob], 'thumb.jpg', { type: 'image/jpeg' });
                setThumbnailFile(generatedFile);
                setThumbnailPreview(URL.createObjectURL(blob));
                setWasAutoGenerated(true);
              }
              setIsGeneratingThumbnail(false);
              resolve();
            }, 'image/jpeg', 0.8);
          } else {
            setIsGeneratingThumbnail(false);
            reject(new Error('Canvas context failed'));
          }
        };

        video.onerror = () => {
          setIsGeneratingThumbnail(false);
          reject(new Error('Video loading failed'));
        };
      });
    };

    capture().catch(err => console.error("Thumbnail gen error:", err));
  }, []);

